INSERT INTO [character_encounter_rules] ([rule_key], [rule_text]) VALUES ('party_size', 'Always 2-5 characters; roll d4 and add 1. Fill to total party size 9 with men-at-arms or henchmen.');
INSERT INTO [character_encounter_rules] ([rule_key], [rule_text]) VALUES ('character_level', 'Character level equals dungeon level or monster level, whichever is greater, through 4th level. After that roll d6+6, adjust one level toward dungeon level, and do not exceed 12 unless dungeon is 16th level or deeper.');
INSERT INTO [character_encounter_rules] ([rule_key], [rule_text]) VALUES ('others', 'Dungeon levels 1-3 may have men-at-arms; dungeon level 4+ uses henchmen. Henchmen class is rolled on Character Subtable, ignoring incompatibilities.');
INSERT INTO [character_encounter_rules] ([rule_key], [rule_text]) VALUES ('abilities_alignment_equipment_spells', 'Abilities, alignment, equipment, and spells are advisory in the source. Preserve as structured notes or use prepared/template parties rather than inventing full NPC sheets.');
INSERT INTO [character_encounter_rules] ([rule_key], [rule_text]) VALUES ('race_multiclass', 'Suggested non-human share is about 20%; race and multiclass rules are advisory and preserved for later expansion.');
