INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (1, 'Axe of the Dwarvish Lords', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A legendary dwarven weapon said to have been forged by the first Dwarven King with divine aid. Its blade functions like a sword of sharpness, its back like a +3 hammer, its haft alters length for different axe forms, and it returns when thrown. It also grants dwarven sensory and trap-related abilities and gradually makes its possessor more dwarf-like.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (2, 'Baba Yaga''s Hut', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A magical hut of ordinary exterior appearance standing on giant fowl legs, but containing a lavish multi-room palace within. It is intelligent, mobile across many terrains, responds to command phrases, and can defend itself with its massive legs.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (3, 'Codex of the Infinite Planes', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An immense and terrifying magical book whose pages hold keys to instant travel to other planes and alternate worlds. It is lethally dangerous to handle or read and is associated with catastrophic magical power and destruction.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (4, 'Crown of Might', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'One of the legendary regalia of alignment, created for champions of Evil, Good, or Neutrality. It grants power only to one of matching ethos, raises the wearer''s effective level, and becomes even more potent when joined with the matching Orb and Sceptre of Might.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (5, 'Crystal of the Ebon Flame', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A beautiful, diamond-hard crystal of unknown origin with a black flame seemingly burning within it. It charms nearby creatures and grants additional powers to the possessor who gazes into its depths.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (6, 'Cup and Talisman of Al''Akbar', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A paired set of holy relics associated with a great lawful good high priest. The Cup is a magnificent jeweled vessel and the Talisman a sacred star-shaped pendant; together, in the hands of suitable holy users, they can produce a powerful sacred potion each week.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (7, 'Eye of Vecna', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The preserved eye of the arch-lich Vecna, appearing as an agate until placed into an empty eye socket, where it permanently grafts itself. It grants darkvision-related powers and other abilities, but forever changes the host to neutral evil.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (8, 'Hand of Vecna', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The mummified left hand of Vecna, which grafts itself onto a severed forearm and becomes a functioning hand of great strength. It grants terrible powers, but progressively corrupts and ultimately turns the host irrevocably to great evil.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (9, 'Heward''s Mystical Organ', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A vast magical organ of legendary power, with many pipes, keys, stops, and pedals, capable of producing mighty magical effects when properly played. It is dangerous to use incorrectly, and its exact workings must be discovered.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (10, 'Horn of Change', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An ancient magical horn resembling lesser enchanted horns, but capable of producing major magical powers or dangerous effects depending on how it is sounded.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (11, 'Invulnerable Coat of Arnd', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A brilliant shirt of nearly weightless chain that renders covered areas totally invulnerable to physical attack and grants extraordinary protection against many elemental and magical harms.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (12, 'Iron Flask of Tuerny the Merciless', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A heavy magical urn sealed with sigils and runes, capable of imprisoning a single extraplanar or terrible being. If opened, its inhabitant may be released and briefly commanded, though always with dangerous consequences.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (13, 'Jacinth of Inestimable Beauty', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A huge fiery orange gemstone of indescribable beauty, said to have been fashioned by the gods. All who see it nearby risk being charmed, and its possessor gains further magical powers.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (14, 'Johydee''s Mask', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A face-covering magical mask associated with the priestess Johydee. It allows the wearer to assume the likeness of human or human-like creatures, blocks mind-affecting contact, and is said to protect against gaze attacks.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (15, 'Kuroth''s Quill', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A magical writing instrument linked to the master thief Kuroth. It can draw and write flawlessly on command, is said to help locate treasure, and bears additional magical powers.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (16, 'Mace of Cuthbert', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A holy mace said to have belonged to Saint Cuthbert himself. It is a mighty lawful good weapon, especially effective in the hands of a suitably strong lawful good cleric.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (17, 'Machine of Lum the Mad', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An ancient and extremely complex mechanism of levers, dials, and switches, capable of producing a vast range of powers and effects. It is fragile, massive, and dangerous to operate without deep knowledge.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (18, 'Mighty Servant of Leuk-O', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A towering magical automaton of unknown ancient manufacture, large enough to carry occupants and serve as transport, war machine, and fighting engine. It is extremely durable, self-repairing, and resistant to magic.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (19, 'Orb of the Hatchling', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The smallest of the Orbs of Dragonkind, able to charm very young dragons. Like all such orbs, it has its own intelligence and ego and may dominate a weak possessor.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (20, 'Orb of the Wyrmling', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm young dragons. It is intelligent, dangerous to weak-willed users, and grants additional magical powers.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (21, 'Orb of the Dragonette', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm sub-adult dragons. It possesses intelligence and ego of its own and can dominate an unfit owner.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (22, 'Orb of the Dragon', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm young adult dragons. It is more powerful than the lesser orbs and increasingly dangerous to its possessor.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (23, 'Orb of the Great Serpent', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm adult dragons. It is highly intelligent, strongly ego-driven, and grants multiple powers and effects.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (24, 'Orb of the Firedrake', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm old dragons. It is more dangerous and more potent than the lesser dragon orbs.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (25, 'Orb of the Elder Wyrm', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An Orb of Dragonkind able to charm very old dragons. It is exceptionally powerful and difficult for a possessor to control safely.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (26, 'Orb of the Eternal Grand Dragon', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The greatest Orb of Dragonkind, able to charm ancient dragons and grant mighty advantages when facing Tiamat or Bahamut. It is extremely intelligent, domineering, and perilous to wield.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (27, 'Orb of Might', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'One of the legendary regalia of alignment, matched to Evil, Good, or Neutrality. It is deadly to those of incompatible ethos and grants further powers, especially when joined to the matching Crown and Sceptre.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (28, 'Queen Ehlissa''s Marvelous Nightingale', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A jeweled mechanical songbird in a fine cage, said to have enthralled all around Queen Ehlissa. It projects a protective field and is rumored to combine magical rays and songs into potent enchantments.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (29, 'Recorder of Ye''Cind', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A magical wind instrument that can play by itself on command. It warns of theft, communicates information through tunes and lyrics, and can work additional magical effects.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (30, 'Ring of Gaxx', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'An alien-looking magical ring with a many-faceted gem that changes function depending on which facet faces upward. Its wearer must discover and manage its shifting powers through use.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (31, 'Rod of Seven Parts', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A shattered artifact made of seven pieces, each leading to the next when properly pursued. Its powers accumulate as correctly ordered parts are joined, and when complete it becomes a weapon of surpassing might.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (32, 'Sceptre of Might', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'One of the legendary regalia of alignment, corresponding to Evil, Good, or Neutrality. It acts as a rod of beguiling and grows stronger when united with the matching Crown and Orb.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (33, 'Sword of Kas', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The infamous sword of Kas, lieutenant and betrayer of Vecna. It is a supremely powerful evil chaotic blade, a +6 defender, especially deadly against extraplanar beings, and possessed of great intelligence and ego.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (34, 'The Teeth of Dahlver-Nar', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A set of sacred teeth from the mighty cleric Dahlver-Nar. Each tooth grants a specific power when grafted into the mouth in place of a missing tooth, and collections of teeth grant cumulative additional benefits.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (35, 'Throne of the Gods', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'A massive jeweled stone throne said to have been sat upon by gods when they walked the world. Those who dare sit in it may gain magical benefits but also suffer malevolent consequences.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (36, 'Wand of Orcus', 'artifact_relic', NULL, NULL, NULL, NULL, NULL, 0, 'The dreadful wand of the demon prince Orcus, sometimes loosed upon the Prime Material Plane to spread chaos and death. It can slay or annihilate victims and grants further terrible powers to its wielder.', NULL, 'artifacts_relics_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (37, 'Alchemy Jug', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical jug that can pour different liquids on command, but only one type of liquid per day, up to 7 pourings. Available liquids include salt water, fresh water, beer, vinegar, wine, ammonia, oil, aqua regia, alcohol, chlorine, and cyanide, with quantity depending on the liquid.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (38, 'Amulet of Inescapable Location', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Appears to prevent location, scrying, or mental detection, but actually doubles the likelihood or range of such location and detection attempts. Normal identification attempts do not reveal its true nature.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (39, 'Amulet of Life Protection', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Protects the wearer’s psyche from possession by magic jar and similar mental attacks. If the wearer dies, the psyche enters the amulet and remains protected for 7 days unless the amulet is destroyed.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (40, 'Amulet of the Planes', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the possessor to transport instantly to or from upper levels of the Outer Planes. Travel is safe, but until the user masters the item, destinations may be random.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (41, 'Amulet of Proof Against Detection and Location', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Wards the wearer against divination, magical location, and mental detection. The wearer cannot be found by clairaudience, clairvoyance, ESP, telepathy, crystal balls, or similar scrying devices.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (42, 'Apparatus of Kwalish', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A metal device that appears to be an iron barrel but unfolds into a lobster-like underwater apparatus with legs, pincers, lights, and controls. It can operate at depths up to 900 feet, hold two human-sized occupants, and function underwater for 2 to 5 hours.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (43, 'Arrow of Direction', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical arrow that, when tossed into the air, falls and points toward a requested route or location such as a stairway, passage, dungeon exit, cave, or cavern. It can be used once per day and will continue pointing for 7 turns.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (44, 'Bag of Beans', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A sack containing pebble-like magical beans. If dumped out, they explode. If removed carefully, planted, and watered, each bean produces a strange magical effect, creature, treasure, or hazard.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (45, 'Bag of Devouring', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed extra-dimensional sack that can act like a bag of holding, but may attempt to swallow living creatures and eventually consume contents. Anything drawn inside is devoured and lost forever.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (46, 'Bag of Holding', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A common-looking sack that opens into a non-dimensional space larger inside than out. Depending on quality, it has fixed weight, weight limit, and volume capacity. If overloaded or pierced, it ruptures and loses its contents forever.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (47, 'Bag of Transmuting', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Appears to be a bag of holding and functions as one for a time, but eventually turns precious metals, gems, and even most magic items placed inside into worthless materials.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (48, 'Bag of Tricks', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A seemingly empty magical bag that produces small fuzzy objects which, when thrown, become obedient animals that fight for the owner. Type of animal depends on the bag and the roll for each use.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (49, 'Beaker of Plentiful Potions', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical beaker that compounds and dispenses several randomly determined potion types. It produces doses on a fixed schedule, but gradually loses one potion type per month after opening.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (50, 'Boat, Folding', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A small wooden box that unfolds by command word into either a 10-foot boat or a 24-foot ship, each with appropriate fittings. Another command word folds it back into box form.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (51, 'Book of Exalted Deeds', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A sacred holy book beneficial to good clerics, granting wisdom and experience if fully read. Characters of other classes or alignments suffer various penalties, injuries, madness, loss of experience, or worse. The book vanishes after one full reading.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (52, 'Book of Infinite Spells', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical book containing many pages, some blank and some holding spells of various classes and levels. Its owner can cast the spell on the open page, and pages may turn unpredictably as spells are used. The book vanishes when the last page is turned.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (53, 'Book of Vile Darkness', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'An evil tome that greatly benefits evil clerics, but harms or corrupts others who read it. Good readers risk death, insanity, and heavy loss, while neutral readers may become evil. It functions as the evil counterpart to the Book of Exalted Deeds.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (54, 'Boots of Dancing', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'Cursed magical boots that at first seem like useful magical boots, but in melee or flight from combat force the wearer into uncontrollable dancing as if affected by Otto’s Irresistible Dance. They can be removed only with remove curse.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (55, 'Boots of Elvenkind', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Soft boots that allow the wearer to move almost completely silently, even over noisy surfaces such as dry leaves or creaking floors.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (56, 'Boots of Levitation', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Magical boots that allow the wearer to ascend or descend vertically at will, with lifting capacity determined randomly.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (57, 'Boots of Speed', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Enable the wearer to move at very high speed, roughly that of a fast horse, with movement reduced by heavy carried weight. They also improve armor class during such movement.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (58, 'Boots of Striding and Springing', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Set the wearer’s base movement at 12 and allow great leaps forward, backward, or upward. They also improve armor class slightly, though acrobatic combat use carries a chance of stumbling.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (59, 'Bowl Commanding Water Elementals', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A stone bowl that, when filled with water and activated with command words, summons a 12-hit-dice water elemental. Salt water produces a stronger elemental.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (60, 'Bowl of Watery Death', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed bowl that resembles one used to command water elementals. When filled, it may shrink the victim and trap them in the water, where they drown unless saved by specific magical means.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (61, 'Bracers of Defense', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'Magical wrist or arm guards that grant an armor class equivalent to wearing armor and a shield, provided no actual armor is worn. Their protective value varies by type.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (62, 'Bracers of Defenselessness', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'Cursed bracers that appear to function as bracers of defense until real danger arises, at which point they reduce armor class to 10 and negate other magical protections and dexterity bonuses.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (63, 'Brazier Commanding Fire Elementals', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A brazier that summons a 12-hit-dice fire elemental when lit and activated with a command word. Adding sulfur makes the elemental stronger.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (64, 'Brazier of Sleep Smoke', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed brazier resembling one that commands fire elementals. When lit, it fills the area with magical sleep smoke and simultaneously summons a hostile fire elemental.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (65, 'Brooch of Shielding', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A piece of jewelry that absorbs damage from magic missiles generated by spells, wands, or similar devices, up to a total of 101 hit points before melting.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (66, 'Broom of Animated Attack', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed broom that seems to be a broom of flying until commanded. It throws off its rider, then attacks as a magical animated broom, blinding and battering its victim.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (67, 'Broom of Flying', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical broom that flies through the air, carries a rider or cargo, travels to named destinations, and comes when called by command word.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (68, 'Bucknard''s Everfull Purse', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical pouch that refills each morning with specific coins, and sometimes small gems, as determined when the purse is first found. If left empty too long, its magic is lost.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (69, 'Candle of Invocation', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A specially blessed candle dedicated to one alignment. Burning it grants a favorable aura to a character of matching alignment, boosts cleric level temporarily if used by a matching cleric, and can also be consumed to power a gate spell.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (70, 'Carpet of Flying', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'An oriental rug that flies when activated by command word and obeys spoken directions. Size, carrying capacity, and speed vary by type.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (71, 'Censer Controlling Air Elementals', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A perforated golden vessel that summons a 12-hit-dice air elemental when filled with incense, lit, and activated. Incense of meditation strengthens the elemental and makes it willingly obedient.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (72, 'Censer of Summoning Hostile Air Elementals', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed censer that resembles other magical censers but instead summons hostile air elementals and cannot be extinguished until either the summoner or the elementals are destroyed.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (73, 'Chime of Opening', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A mithral chime that opens locks, doors, lids, valves, portals, and similar closures when struck and pointed properly. It can also negate hold portal and lower-level wizard lock effects. It has limited charges.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (74, 'Chime of Hunger', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed chime that resembles a chime of opening. When struck, it causes creatures in the area to become ravenously hungry, forcing them to eat or attack others for food.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (75, 'Cloak of Displacement', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A cloak that distorts light so the wearer appears 1 to 2 feet from their actual position. The first attack misses automatically, and later attacks suffer improved armor class and saving throw penalties against the wearer.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (76, 'Cloak of Elvenkind', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A gray cloak with chameleon-like properties that renders the wearer nearly invisible when the hood is drawn, especially in natural surroundings and darkness.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (77, 'Cloak of the Manta Ray', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A leather-like cloak that transforms underwater into a manta ray-like form, allowing the wearer to breathe underwater, swim quickly, and attack with a tail spine.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (78, 'Cloak of Poisonousness', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed cloak that appears magical but harmless until worn, at which point the wearer dies from poison. It can be removed only with remove curse.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (79, 'Cloak of Protection', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A cloak that grants bonuses to armor class and saving throws, with strength varying by type. It does not function with most armor or shields.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (80, 'Crystal Ball', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical scrying sphere that allows a magic-user to view distant places or even other planes, depending on how well the subject is known. Some crystal balls also grant clairaudience, ESP, or telepathy.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (81, 'Crystal Hypnosis Ball', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed crystal ball that appears normal but hypnotizes users and implants telepathic suggestions, gradually bringing them under the influence of a powerful being.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (82, 'Cube of Force', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A small cube that creates a cubic force screen around the user. Different faces block different categories of matter, energy, or magic, and maintaining the screen consumes charges.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (83, 'Cube of Frost Resistance', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A cube that encloses a small area in a temperate field and absorbs cold-based attacks. Too much cold damage in a short time causes the field to collapse or destroys the cube.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (84, 'Cubic Gate', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A small carnelian cube with six faces keyed to planes. Pressing a face opens a nexus to the corresponding plane; pressing twice transports nearby creatures through it.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (85, 'Daern''s Instant Fortress', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A small metal cube that expands into a 20-foot square adamantite tower with battlements and an owner-commanded door. It is highly durable but not repairable except by wish.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (86, 'Decanter of Endless Water', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical flask that pours fresh or salt water on command in stream, fountain, or geyser form. The geyser setting exerts strong back pressure and can kill very small creatures.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (87, 'Deck of Many Things', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A legendary magical deck whose drawn cards produce dramatic beneficial or disastrous effects such as wishes, treasure, alignment change, imprisonment, death, madness, or other fate-altering results.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (88, 'Horn of Blasting', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical horn that produces a cone of sound stunning and deafening creatures within it, while also generating an ultrasonic wave that weakens or destroys stone, wood, and metal structures. Repeated magical use risks explosion or self-shattering.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (89, 'Horn of Bubbles', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical horn that creates a mass of bubbles which surround and blind the blower for 2 to 20 rounds, but only when a creature actively seeking to slay that character is present.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (90, 'Horn of Collapsing', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A horn that, if sounded incorrectly or by mishap, causes a collapse upon the user from above. When properly used, it can collapse a section of roof or ceiling at range.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (91, 'Horn of the Tritons', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A conch shell horn usable once per day, or three times daily by a triton. It can calm rough water, summon certain marine creatures, or panic low-intelligence marine life.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (92, 'Horn of Valhalla', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical horn that summons berserk fighters from Valhalla to serve the blower in battle. The type of horn determines how many and how powerful the warriors are, and who may safely use it.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
