INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (144, 'Robe of Powerlessness', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed robe that reduces the wearer''s intelligence and strength to 3, erasing magical knowledge and spells until remove curse and heal are used.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (145, 'Robe of Scintillating Colors', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical robe that can erupt in dazzling shifting colors, hypnotizing enemies, making attacks against the wearer harder, and still allowing limited activity including spellcasting.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (146, 'Robe of Useful Items', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A robe covered with magical cloth patches that can be detached and transformed into useful actual items such as ropes, ladders, doors, treasure, animals, boats, potions, and more.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (147, 'Rope of Climbing', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A strong magical rope that can move, attach itself, return, or knot itself on command, making it useful for climbing and similar tasks.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (148, 'Rope of Constriction', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed magical rope that appears beneficial but instead wraps itself around the holder and nearby creatures, crushing and strangling them until dispelled or cut.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (149, 'Rope of Entanglement', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical rope that lashes out on command to bind multiple creatures. It is extremely hard to cut and repairs lesser damage unless fully severed.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (150, 'Rug of Smothering', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed rug resembling a carpet of flying that instead wraps itself around a victim and suffocates them unless stopped by powerful magic.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (151, 'Rug of Welcome', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical rug that functions as a carpet of flying but can also act as a smothering trap, a rigid bridge or barricade, and can shrink for easy transport.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (152, 'Saw of Mighty Cutting', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A massive adamantite saw requiring exceptional strength to use. It cuts through trees and timber rapidly but is exhausting to operate.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (153, 'Scarab of Death', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed scarab that turns into a burrowing beetle if kept too near a living body, then bores into the victim''s heart and kills them before returning to scarab form.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (154, 'Scarab of Enraging Enemies', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical scarab that enrages intelligent hostile creatures within range, driving them into berserk fury. It has a limited number of charges.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (155, 'Scarab of Protection', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A protective magical device that grants +1 on all saving throws versus magic and even allows a save against certain effects that normally permit none. It can also absorb up to 12 life-draining or death effects before turning to powder. Rare reversed cursed versions impose penalties instead.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (156, 'Spade of Colossal Excavation', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A huge magical digging tool usable by a fighter with 18 strength. It excavates earth with exceptional speed, though harder materials take longer and the user must rest regularly.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (157, 'Sphere of Annihilation', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A 2-foot globe of absolute blackness that destroys any matter touching it utterly. A magic-user can attempt to control its movement by mental effort, with success depending on intelligence and level.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (158, 'Talisman of Pure Good', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A holy talisman usable by a good high priest or priestess to destroy an evil cleric by opening a flaming crack beneath the victim. It has 7 charges and cannot be recharged.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (159, 'Talisman of the Sphere', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'An adamantite loop and handle usable only by magic-users. It greatly improves control over a Sphere of Annihilation, doubling intelligence-based control bonuses and reducing how often continued control must be checked.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (160, 'Talisman of Ultimate Evil', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A device identical in appearance to a Talisman of Pure Good, but opposite in effect and alignment. It has 6 charges.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (161, 'Talisman of Zagy', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A mysterious talisman whose effects depend on the holder''s charisma and reaction result. It may act as a burden, grant one or more wishes, warn of nearby traps, and eventually vanish leaving behind a valuable gem.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (162, 'Tome of Clear Thought', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical tome that, after reading and one month of mental discipline, increases the reader''s intelligence by 1 point. It disappears after reading and cannot benefit the same character more than once.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (163, 'Tome of Leadership and Influence', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical tome similar to a Tome of Clear Thought, but increasing charisma by 1 point after study and practice.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (164, 'Tome of Understanding', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical tome similar to a Tome of Clear Thought, but increasing wisdom by 1 point after study and practice.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (165, 'Trident of Fish Command', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical trident that can command fish within a 6-inch radius if they fail a saving throw versus magic. Controlled fish will not attack the wielder or nearby allies and can be directed by empathic impulse.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (166, 'Trident of Submission', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical trident that forces struck opponents to save versus magic or become overwhelmed with hopelessness, potentially ceasing combat and surrendering for a time. It is otherwise a +1 weapon.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (167, 'Trident of Warning', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical trident that detects hostile or hungry marine predators within 24 inches, revealing their location, depth, species, and number. It is otherwise a +2 magical weapon.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (168, 'Trident of Yearning', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed trident that compels anyone grasping it to seek the deepest available water and immerse themselves completely. The victim cannot release it without powerful magic. It is otherwise a -2 cursed magical weapon.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (169, 'Vacuous Grimoire', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed magical book that appears ordinary but causes intelligence and wisdom loss to anyone reading even a single glyph unless saving throws are made. It changes appearance to match nearby books and must be cursed-removed and burned to be destroyed.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (170, 'Well of Many Worlds', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A strange inter-dimensional device resembling a portable hole. Anything placed inside is sent instantly to another world, plane, or parallel earth, and things from the destination may also come through.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (171, 'Wings of Flying', 'misc_magic_item', NULL, NULL, NULL, NULL, NULL, 0, 'A magical black cloak that transforms into giant bat-like wings when commanded. It allows flight at different speeds for limited durations, after which the wearer must rest.', NULL, 'misc_magic_items_master.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (172, 'Rod of Absorption', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Absorbs spells directed at the wielder, nullifying them and storing their spell levels as energy. The wielder can then cast memorized spells of equal or lower level in 1 segment without losing spell memory. The rod holds up to 50 spell levels total and cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (173, 'Rod of Beguiling', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Causes intelligent creatures within a 2-inch radius to regard the wielder as a trusted friend, comrade, or mentor, with no saving throw. The effect lasts 1 turn per charge. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (174, 'Rod of Cancellation', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Drains a magic item of all magical properties by touch unless the item succeeds on a saving throw. The rod becomes brittle and useless after draining an item. Drained items cannot be restored, even by wish.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (175, 'Rod of Lordly Might', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'A versatile magic rod with spell-like powers, weapon transformations, and practical functions. It can paralyze, cause fear, drain hit points, function as several magic weapons, become a climbing pole or door-forcing lever, and indicate magnetic north and depth. Some functions use charges; others do not. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (176, 'Rod of Resurrection', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Allows a cleric to resurrect the dead, including demi-humans, as if of sufficient level to cast the spell, without requiring rest afterward. The rod can be used once per day. Charge cost depends on the class and race of the one being resurrected. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (177, 'Rod of Rulership', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wielder to command the obedience and fealty of creatures within 12 inches. It can rule 200 to 500 hit dice or levels, though stronger intelligent creatures may receive a saving throw. Each charge lasts 1 turn. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (178, 'Rod of Smiting', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'A +3 magic weapon that deals 4 to 11 damage. It deals extra damage to golems and certain extraplanar creatures, with special charge-draining effects on powerful hits. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (179, 'Staff of Command', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Has three powers: human influence, mammal or animal control, and plant control. Some powers depend on whether the wielder is a magic-user or a cleric. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (180, 'Staff of Curing', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can cure disease, blindness, wounds, or insanity. Each use costs 1 charge. It may be used only once per day on any given person, and no single function may be employed more than twice per day. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (181, 'Staff of the Magi', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'A powerful staff with many spell powers, magical defenses, spell absorption, and the ability to unleash a devastating retributive strike if broken. It grants bonuses on saving throws versus magic and can only be recharged by absorbing spell energy.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (182, 'Staff of Power', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'A potent staff with both offensive and defensive magical powers, including light, darkness, ray of enfeeblement, levitation, magic missile, lightning bolt, cone of cold, fireball, shield, globe of invulnerability, and paralyzation. It also grants armor class and saving throw bonuses, can strike as a magic weapon, and can be broken for a retributive strike. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (183, 'Staff of the Serpent', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Comes in two forms: python and adder. The python form can become a giant constrictor snake; the adder form can transform its head into a poisonous serpent. Neither type uses charges.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (184, 'Staff of Striking', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'An oaken +3 magic weapon that deals 4 to 9 damage on a hit. Additional charges can be spent to increase bonus damage. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (185, 'Staff of Withering', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'A +1 magic weapon that deals 2 to 5 damage. Charges can also be spent to age the target or wither one of its limbs unless the victim saves versus magic. It can be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (186, 'Wand of Frost', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can produce ice storm, wall of ice, or cone of cold effects. Each function uses charges, with cone of cold costing 2 charges.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (187, 'Wand of Conjuration', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Allows recognition of conjuration and summoning magic and can create unseen servants, monster summoning effects, a curtain of total blackness, or a prismatic sphere or wall one color at a time. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (188, 'Wand of Enemy Detection', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Pulses and points toward any hostile creature intending harm to the bearer, even if invisible, hidden, ethereal, astral, or disguised. Its range is a 6-inch sphere. Each use lasts 1 turn and costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (189, 'Wand of Fear', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Projects a pale amber cone that causes creatures struck to flee as if affected by a fear spell unless they save versus wands. Each use costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (190, 'Wand of Fire', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can produce burning hands, pyrotechnics, fireball, or wall of fire effects, depending on the function chosen. Each use costs charges according to the effect. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (191, 'Wand of Illumination', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can create dancing lights, light, continual light, or a sunburst. The sunburst damages undead and may blind creatures in the area. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (192, 'Wand of Illusion', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Creates audible and visual illusions similar to audible glamer and phantasmal force. The wielder must concentrate to maintain the effect. Charges are spent to create and continue each portion of the illusion. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (193, 'Wand of Lightning', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can deliver a shock in melee or fire a lightning bolt similar to the spell. The shock costs 1 charge, while lightning bolt costs 2 charges. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (194, 'Wand of Magic Detection', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Pulses and points toward the strongest nearby magical source within a 3-inch radius. Continued use can identify weaker sources and determine the school of magic, but prolonged operation has a cumulative chance of temporary malfunction. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (195, 'Wand of Metal and Mineral Detection', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Pulses and points toward the largest nearby mass of metal within a 3-inch radius, or toward a specified metal or mineral if the wielder concentrates on one. It also reveals approximate quantity. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (196, 'Wand of Magic Missiles', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Fires magic missiles that behave like the spell of the same name and deal 2 to 5 damage each. Magic-users always hit; others require a hit roll. Each missile costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (197, 'Wand of Negation', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Negates the spell or spell-like functions of rods, staves, wands, and other magical devices. Each use costs 1 charge. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (198, 'Wand of Paralyzation', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Fires a thin blue ray up to 6 inches that paralyzes one creature for 5 to 20 rounds unless the target saves versus wands. Each use costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (199, 'Wand of Polymorphing', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Can polymorph another creature at range as polymorph other, or transform a touched creature as polymorph self. Each function costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (200, 'Wand of Secret Door and Trap Location', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Pulses and points to either a secret door or a trap within range, depending on which function is chosen. It requires 1 round to operate and costs 1 charge. It may be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (201, 'Wand of Wonder', 'rod_staff_wand', NULL, NULL, NULL, NULL, NULL, 0, 'Produces one of many strange, random magical effects each time it is used, ranging from weather, darkness, and invisibility to fireballs, lightning bolts, enlargement, petrification, or other unpredictable results. Each use costs 1 charge. It cannot be recharged.', NULL, 'rods_staves_wands_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (202, 'Ring of Contrariness', 'ring', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed ring that makes the wearer unable to agree with any idea, statement, or action. It can be removed only after a remove curse spell, though the wearer will resist removal. It also grants one additional magical property such as flying, invisibility, levitation, shocking grasp, spell turning, or strength.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (203, 'Ring of Delusion', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Convinces the wearer that it is some other desired magical ring. The wearer may unconsciously use personal abilities or other resources to imitate the supposed powers. The ring can be removed at any time.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (204, 'Djinni Summoning', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'A legendary ring that serves as a gate to summon a particular djinni from the Elemental Plane of Air. When rubbed, the djinni appears on the next round and faithfully serves the ring wearer. If the servant is ever killed, the ring becomes non-magical and worthless.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (205, 'Ring of Elemental Command', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'A powerful ring attuned to one elemental plane. It protects the wearer from elementals of that plane, may allow attempts to charm them, enables communication with elemental beings, grants strong combat advantages against them, and imposes a saving throw penalty against the opposing force. Each ring also has additional powers depending on whether it is attuned to air, earth, fire, or water.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (206, 'Ring of Feather Falling', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Automatically activates feather fall if the wearer falls 5 feet or more.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (207, 'Ring of Fire Resistance', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Grants total immunity to normal fires. Against intense supernatural or magical fire, it provides greatly reduced damage and improved saving throws.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (208, 'Ring of Free Action', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to move and attack freely despite effects such as web, hold, or slow, and to function normally underwater in combat, though it does not grant water breathing.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (209, 'Ring of Human Influence', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Raises the wearer’s charisma to 18 for reactions involving humans and humanoids. It also allows suggestion once per day and charm person-like effects on up to 21 levels or hit dice of humans or humanoids once per day.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (210, 'Ring of Invisibility', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to become invisible instantly at will, functioning like the invisibility spell. Some examples also grant inaudibility, making the wearer absolutely silent unless speaking.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (211, 'Ring of Mammal Control', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows complete control over mammals with intelligence 4 or less, up to 30 hit dice total. Full concentration is required, and commanded creatures can even be driven to self-destruction.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (212, 'Ring of Multiple Wishes', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Contains 2 to 8 wish spells. Each wish is expended whether or not it is granted successfully, and the exact fulfillment depends on the wording and the referee’s interpretation.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (213, 'Ring of Protection', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Improves the wearer’s armor class and saving throws against all forms of attack. Its protective value varies, and saving throw bonuses can extend in a 5-foot radius for some versions.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (214, 'Ring of Regeneration', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Usually restores 1 hit point per turn and can eventually regrow lost limbs or organs, even restoring life unless total bodily destruction prevents it. A rare vampiric form instead heals the wearer by half the melee damage dealt to opponents.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (215, 'Ring of Shooting Stars', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Functions only in relative darkness. Outdoors at night it can produce dancing lights, light, ball lightning, and shooting stars. Indoors at night or underground it can produce faerie fire and a damaging spark shower.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (216, 'Ring of Spell Storing', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Contains 2 to 5 spells which the wearer can cast as though personally able to use them. Once cast, stored spells must be replaced by an appropriate spellcaster.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (217, 'Ring of Spell Turning', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Turns part or all of spells cast directly at the wearer back upon the caster. Area spells, touch spells, and device-triggered magic are not turned. The exact portion reflected is determined randomly.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (218, 'Ring of Swimming', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to swim at full speed, dive safely to significant depths, remain underwater for several rounds without breathing, and stay afloat except in extreme conditions.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (219, 'Ring of Telekinesis', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to move objects by telekinesis in the same manner as the spell, with the maximum weight determined randomly.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (220, 'Ring of Three Wishes', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Contains 3 wish spells. Otherwise it functions like a ring of multiple wishes, except that some examples instead contain 3 limited wish spells.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (221, 'Ring of Warmth', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Keeps the wearer warm even in extreme cold, restores cold damage at 1 hit point per turn, improves saving throws against cold by +2, and reduces cold damage by 1 per die.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (222, 'Ring of Water Walking', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to walk on any liquid surface, including water, mud, quicksand, oil, and snow, without sinking. It can support up to 1,200 pounds.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (223, 'Ring of Weakness', 'ring', NULL, NULL, NULL, NULL, NULL, 1, 'A cursed ring that causes the wearer to lose 1 point of strength and 1 point of constitution per turn until reaching 3 in each. It also grants invisibility at will, which doubles the rate of loss. A rare reversed form grants berserk strength instead.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (224, 'Ring of Wizardry', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Usable only by magic-users. It doubles the number of spells the wearer may prepare each day in one or more spell levels, with the exact effect determined randomly.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (225, 'Ring of X-Ray Vision', 'ring', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the wearer to see through many substances within a 20-foot range, revealing hidden compartments, doors, and objects. Overuse drains constitution, requiring rest to recover.', NULL, 'rings_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (226, 'Animal Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Enables the imbiber to empathize with and control the emotions of one type of animal, such as cats, dogs, or horses. Number controlled depends on size. Intelligent animals may receive a saving throw versus magic. Control is limited to emotions or drives unless communication is possible.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (227, 'Clairaudience', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Empowers the drinker to hear as the 3rd-level magic-user spell clairaudience. Can be used to clairaudit unknown areas within 3 inches. Effects last 2 turns.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (228, 'Clairvoyance', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Empowers the drinker to see as the 3rd-level magic-user spell clairvoyance. Unlike the spell, unknown areas up to 3 inches distant can be seen. Effects last 1 turn.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (229, 'Climbing', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Enables the imbiber to climb up or down vertical surfaces with only a base 1% chance of falling. Additional slipping chances apply for weight carried and armor worn. Effective for 1 turn plus 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (230, 'Delusion', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Causes the drinker to believe the liquid is some other potion, such as healing. The apparent effect is only imagined, and only later events reveal the truth.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (231, 'Diminution', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Causes the drinker and all worn and carried gear to shrink in size. A full potion reduces size to as small as 5% of normal; half a potion shrinks the person to 50%. Effects last 6 turns plus 2 to 5 additional turns.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (232, 'Dragon Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Acts like a charm monster spell on a dragon type determined by the potion. Dragons are entitled to a saving throw versus magic at -2. Control lasts 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (233, 'ESP', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Bestows the ability of the magic-user spell ESP, except that its duration is 5 to 40 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (234, 'Extra-Healing', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Restores 6 to 27 hit points when wholly consumed, or 1 to 8 hit points for each one-third of the potion.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (235, 'Fire Resistance', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Confers magical invulnerability to normal fire and resistance to intense magical or supernatural fire. Damage from such fire is reduced by 2 per die, and applicable saving throws are made at +4. Half a potion gives reduced benefits. Duration is 1 turn, or 5 rounds for a half dose.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (236, 'Flying', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the drinker to fly in the same manner as the 3rd-level magic-user spell fly.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (237, 'Gaseous Form', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Transforms the drinker and worn and carried gear into transparent, insubstantial gas able to flow through non-airtight openings. Vulnerable to magical fire and lightning, and especially to whirlwinds. Effects last for the full duration of the potion.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (238, 'Giant Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'A full potion influences 1 or 2 giants as if by charm monster. Saving throw modifiers depend on whether 1 or 2 giants are affected. Giant type is randomly determined. Control lasts 5 to 30 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (239, 'Giant Strength', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Grants giant-like strength, increased damage bonuses, and rock-hurling ability according to a randomly determined giant type. Usable only by fighters.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (240, 'Growth', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Causes the drinker, garments, and carried gear to enlarge in size. Strength increases enough to bear enlarged armor and weapons, but does not add combat bonuses. Each quarter potion adds 6 feet of height, for up to 24 feet with a full potion.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (241, 'Healing', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Restores 4 to 10 hit points of damage when the entire potion is consumed in a single round.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (242, 'Heroism', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Temporarily increases the life energy levels of a character with fewer than 10 levels of experience, granting additional effective levels and hit dice. Damage is taken first from the magically gained hit dice. Restricted to men-at-arms and fighters.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (243, 'Human Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the imbiber to control up to 32 levels or hit dice of humans, humanoids, and demi-humans as if by charm person. Eligible targets receive saving throws versus magic. Type of beings controlled is randomly determined. Duration is 5 to 30 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (244, 'Invisibility', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Confers invisibility like the spell of the same name. A single gulp equal to one-eighth of the potion grants invisibility for 3 to 6 turns.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (245, 'Invulnerability', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Grants immunity to non-magical weapons and attacks from non-magical creatures or creatures with fewer than 4 hit dice. Also improves armor class by 2 and saving throws by +2. Only fighters can use this potion. Duration is 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (246, 'Levitation', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the drinker to levitate in the same manner as the 2nd-level magic-user spell, subject to a maximum weight of 6,000 gp equivalent.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (247, 'Longevity', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Reduces the drinker’s game age by 1 to 12 years and restores youth and vigor, but each use adds a cumulative 1% chance of reversing all age reduction gained from earlier longevity potions.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (248, 'Oil of Etherealness', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'A light oil applied externally that confers etherealness after 3 rounds. The user can pass through solid objects and becomes invisible to non-ethereal beings. Duration is 4 plus 1 to 4 turns unless removed early with a weak acidic solution.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (249, 'Oil of Slipperiness', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Applied externally, this oil prevents the user from being grabbed, constricted, or held by webs, ropes, chains, and similar restraints. If poured on a surface, creatures standing there have a 95% chance per round to slip and fall. Lasts 8 hours unless removed with alcohol.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (250, 'Philter of Love', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Causes the drinker to become charmed by the first creature seen after drinking, or enamored and charmed if that creature is of similar race and opposite sex. Charming lasts 4 plus 1 to 4 turns; enamoring lasts until dispelled.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (251, 'Philter of Persuasiveness', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Makes the drinker more charismatic, giving a 25% bonus on reaction rolls. Also allows the user to make a suggestion once per turn to creatures within 3 inches.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (252, 'Plant Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the drinker to influence vegetable life forms, including plants, fungi, molds, and shambling mounds, within their normal abilities. Intelligent plant creatures may save versus magic. Control range is 9 inches, affecting a 2-inch by 2-inch area for 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (253, 'Poison', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'A highly toxic liquid in a potion flask. Ingestion, entry through broken skin, or even skin contact may cause death. Toxicity can vary from weak to deadly.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (254, 'Polymorph (Self)', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Duplicates the effects of the 4th-level magic-user spell polymorph self in most respects.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (255, 'Speed', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Doubles movement and combat capability, allowing additional attacks, though it does not reduce spell casting time. Use of the potion permanently ages the imbiber by 1 year. Other effects last 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (256, 'Super-Heroism', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Like heroism but stronger, granting a temporary increase in life energy levels to characters with fewer than 13 levels of experience. Effects otherwise resemble heroism and last 5 to 30 melee rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (257, 'Sweet Water', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Not intended to be drunk, though harmless if consumed. Added to liquids, it transforms polluted, salt, alkaline, or acidic water into pure drinkable water. It also neutralizes poison and ruins magic potions. Effects are permanent, though water can later be contaminated again.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (258, 'Treasure Finding', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Gives the drinker a sense of the direction of the nearest mass of valuable treasure within 24 inches, provided the treasure meets minimum quantity thresholds. The potion reveals direction but not distance. Effects last 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (259, 'Undead Control', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Allows the imbiber to charm certain undead, affecting up to 16 hit dice total. Intelligent undead may save versus magic at -2. Type of undead affected is determined randomly. Effects last 5 to 20 rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_items] ([magic_item_id], [name], [item_type], [subtype], [bonus], [charges], [value_gp], [rarity], [curse_flag], [description], [notes], [source_file], [imported_at]) VALUES (260, 'Water Breathing', 'potion', NULL, NULL, NULL, NULL, NULL, 0, 'Usually contains 2 doses, with a lesser chance of 4 doses. Each dose allows the drinker to breathe normally in oxygenated liquids for 1 hour plus 1 to 10 additional rounds.', NULL, 'potions_two_field.csv', '2026-04-12 19:50:09');
INSERT INTO [magic_weapon_hit_requirements] ([requirement_id], [defender_requires], [attacker_weapon_bonus_required], [attacker_hit_dice_required], [notes]) VALUES (1, '+1 or better', '+1 or better', '4+1 or more', '');
INSERT INTO [magic_weapon_hit_requirements] ([requirement_id], [defender_requires], [attacker_weapon_bonus_required], [attacker_hit_dice_required], [notes]) VALUES (2, '+2 or better', '+2 or better', '6+2 or more', '');
INSERT INTO [magic_weapon_hit_requirements] ([requirement_id], [defender_requires], [attacker_weapon_bonus_required], [attacker_hit_dice_required], [notes]) VALUES (3, '+3 or better', '+3 or better', '8+3 or more', '');
INSERT INTO [magic_weapon_hit_requirements] ([requirement_id], [defender_requires], [attacker_weapon_bonus_required], [attacker_hit_dice_required], [notes]) VALUES (4, '+4 or better', '+4 or better', '10+4 or more', '');
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (1, 'Aerial Servant', NULL, 'Very rare', '1', '3', '24"', '16', '0', 'Nil', '1', '8-32', 'grapple; carry victims through the air', 'can be hit only by magic weapons', 'Standard', 'Semi-intelligent', 'Neutral', 'L (8'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Aerial_Servant.png', 'images/monsters/Aerial_Servant.png', 'Invisible servant of the elemental plane of air, conjured by clerics. Extremely strong and fast, it attacks by seizing and carrying victims aloft. If freed or it completes its task, it returns to its plane.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (2, 'Basilisk', NULL, 'Uncommon', '1-4', '4', '6"', '6 + 1', '40%', 'F', '1', '1-10', 'gaze turns to stone', 'Nil', 'Standard', 'Animal', 'Neutral', 'M (7'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Basilisk.png', 'images/monsters/Basilisk.png', 'Reptilian monster with a petrifying gaze; slow-moving but deadly. Oils from its stomach can reverse petrification if properly prepared.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (3, 'Black Bear', NULL, 'Common', '1-3', '7', '12"', '3 + 3', 'Nil', 'Nil', '3', '1-3/1-3/1-6', 'hugs for 2-8', 'Nil', 'Standard', 'Semi-intelligent', 'Neutral', 'M (6'' + tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Black_Bear.png', 'images/monsters/Black_Bear.png', 'Omnivorous bear with excellent hearing and smell. Aggressive when hungry or provoked; can hug for extra damage after successful claw attacks.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (4, 'Brown Bear', NULL, 'Uncommon', '1-6', '6', '12"', '5 + 5', 'Nil', 'Nil', '3', '1-6/1-6/1-8', 'hugs for 2-12', 'Nil', 'Standard', 'Semi-intelligent', 'Neutral', 'L (9'' + tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Brown_Bear.png', 'images/monsters/Brown_Bear.png', 'Large, aggressive bear. Powerful claws and bite, with crushing hug attacks after successful claw strikes.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (5, 'Cave Bear', NULL, 'Uncommon', '1-2', '6', '12"', '6 + 6', 'Nil', 'Nil', '3', '1-8/1-8/1-12', 'hugs for 2-16', 'Nil', 'Standard', 'Semi-intelligent', 'Neutral', 'L (12'' + tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Cave_Bear.png', 'images/monsters/Cave_Bear.png', 'Gigantic cave-dwelling bear, stronger than other common bears. Deadly in melee and capable of powerful hugging attacks.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (6, 'Black Pudding', NULL, 'Rare', '1', '6', '6"', '10', 'Nil', 'Nil', '1', '3-24', 'dissolves organic material; corrodes metal', 'immune to cold; splits when struck', 'Standard', 'Non-', 'Neutral', 'L (variable)', 'Nil', 'Nil', NULL, NULL, NULL, 'Black_Pudding.png', 'images/monsters/Black_Pudding.png', 'Amorphous black scavenger composed of single-cell organisms, found underground. Moves along walls and ceilings as easily as floors. Attacks by dissolving flesh and organic matter and corrodes metal armor. Cold has no effect. When struck, it can split into multiple attacking parts.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (7, 'Beholder', NULL, 'Very rare', '1', '0/2/7', '3"', '45-75 hp', '80%', 'I,S,T', '1', '2-8', '11 eye rays: charm person; charm monster; sleep; telekinesis (2,500 gp wt.); flesh to stone (3" range); disintegrate (2" range); fear (as a wand); slow; cause serious wounds (5" range); death ray (4" range); anti-magic ray (14" range)', 'central anti-magic eye; eyestalks AC 2; body AC 0; difficult to surprise', 'Special', 'Exceptional', 'Lawful evil', 'L (4-6'' diameter)', 'Nil', 'Nil', NULL, NULL, NULL, 'Beholder.png', 'images/monsters/Beholder.png', 'A floating spherical creature with a large central eye and ten eyestalks, each producing a different magical ray. The central eye emits an anti-magic cone that negates magic and prevents its own eyestalk rays from functioning within that area. Eyestalks and central eye have separate durability; damage can disable individual rays before the creature is destroyed. Each eyestalk can project its power depending on facing and angle, allowing multiple effects in a round, while attacks from above may limit stalk usage. The creature’s body accounts for most of its durability, with eye structures taking partial damage before loss of function. Beholders are highly intelligent, hateful, aggressive, and avaricious. They usually attack immediately but may negotiate or accept bribes when faced with strong opposition. They dwell underground, hoard treasure, and can speak their own language as well as that of lawful evil creatures.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (8, 'Boar (Wild)', NULL, 'Common', '2-12', '7', '15"', '3+3', 'Nil', 'Nil', '1', '2-8', 'charge; continues fighting below 0 hp', 'Nil', 'Standard', 'Animal', 'Neutral', 'M (3'' at shoulder)', 'Nil', 'Nil', NULL, NULL, NULL, 'Boar_Wild.png', 'images/monsters/Boar_Wild.png', 'Wild boars attack with a powerful gore. If more than one is encountered, most will be sows (2–8 hp, 3 hit dice, 2–8 damage), with a ratio typically including multiple sows per boar. Boars are extremely tenacious and will continue fighting for 2–5 melee rounds even after reaching 0 to -6 hit points, dying only when reduced to -7 or lower. They are aggressive and dangerous when wounded or cornered.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (9, 'Giant Boar', NULL, 'Uncommon', '1-8', '6', '15"', '7+7', 'Nil', 'Nil', '1', '3-12', 'charge; continues fighting below 0 hp', 'Nil', 'Standard', 'Animal', 'Neutral', 'L (5'' at shoulder)', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Boar.png', 'images/monsters/Giant_Boar.png', 'A larger and more dangerous relative of the wild boar, this creature attacks with a devastating gore. It shares the same relentless nature, continuing to fight for several melee rounds after reaching 0 to -6 hit points before finally dying. Giant boars are stronger, more durable, and more aggressive than their smaller counterparts, making them highly dangerous in melee combat.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (10, 'Brownie', NULL, 'Rare', '4-16', '3', '12"', '1/2', '20%', 'O, P, Q', '1', '1-3', 'spells (protection from evil, ventriloquism, dancing lights, continual light, mirror image, confusion, dimension door)', 'save as 9th level cleric; never surprised; blending into landscape to become effectively invisible', 'As above', 'High', 'Lawful good', 'S (1.5'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Brownie.png', 'images/monsters/Brownie.png', 'Brownies are distant relatives of halflings, smaller and much less common. They are shy but generally friendly to humans, dwarves, elves, and halflings, favoring quiet pastoral places. On friendly terms they can often be convinced to aid lawful good characters, and they are good guides and skilled makers or repairers of wood, leather, and metal goods. Each brownie can use once per day: protection from evil, ventriloquism, dancing lights, continual light, mirror image (3 images), confusion, and dimension door. They usually carry only short swords, have exceptional senses, are never surprised, and have 18 dexterity. Brownies can blend into natural surroundings so quickly that they are effectively invisible. They speak their own language, the alignment tongue, elvish, pixieish, and the languages of sprites and halflings.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (11, 'Bugbear', NULL, 'Uncommon', '6-36', '5', '9"', '3+1', '25%', 'Individuals J, K, L, M; B in lair', '1', '2-8 or by weapon', 'surprise on 1-3', 'Nil', 'Standard', 'Low to Average (low)', 'Chaotic evil', 'L (7''+ tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Bugbear.png', 'images/monsters/Bugbear.png', 'Bugbears are large, hairy goblinoids known for their stealth and ambush tactics despite their size. They operate equally well in bright daylight or darkness due to infravision and live above or below ground. For larger groups, chiefs and leaders appear with higher hit points and damage, while females and young remain in lairs. They use a wide variety of weapons, from swords to spiked wooden clubs, and often hurl spears, axes, maces, and hammers. Though clumsy-looking, they move quietly and surprise opponents 50% of the time. They speak goblin and hobgoblin in addition to their racial and alignment tongues. Their dull yellow to yellow-brown skin, greenish-white eyes with red pupils, and dirty hides and armor make them distinctive.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (12, 'Centaur', NULL, 'Rare', '4-24', '5 (4)', '18"', '4', '5%', 'M, Q (with each); D, I, T in lair', '2', '1-6/1-6', 'human weapon use; rear kick/hoof attacks in melee', 'Nil', 'Standard', 'Low-Average', 'Neutral-Chaotic good', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Centaur.png', 'images/monsters/Centaur.png', 'Centaurs dwell in secluded pastures far from human settlements. Roving bands always carry weapons; half use clubs, one-quarter use composite long bows, and the remainder are leaders with shields and lances. In melee they attack with weapon and forehooves. In lairs, hidden glens contain additional males, females, and young; females and young fight only in desperation. If their families are threatened, centaurs are 90% likely to ransom them with treasure. They speak their own language and that of their alignment. Centaurs are generally not friendly to humans or dwarves, tolerate gnomes and halflings, and are friendly with elves, especially wood elves.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (13, 'Giant Centipede', NULL, 'Common', '2-24', '9', '15"', '1/4', 'Nil', 'Nil', '1', 'Nil', 'poison (+4 to victim''s save); fast leap/bite behavior', 'Nil', 'Standard', 'Non-', 'Neutral', 'S (1''+ long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Centipede.png', 'images/monsters/Giant_Centipede.png', 'Giant centipedes are aggressive vermin found almost everywhere. Their bite causes little or no physical damage but injects weak poison, with victims receiving +4 on the saving throw. Because the creature is small, attacks that permit a saving throw against it gain a -1 on the die. Colors range from pale gray to black, red to brown.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (14, 'Chimera', NULL, 'Rare', '1-4', '6/5/2', '9"/18"', '9', '40%', 'F', '6', '1-3/1-3/1-4/1-4/2-8/3-12', 'breath weapon (50% chance; 5" range; 3-24 damage, save for half)', 'Nil', 'Standard', 'Semi-intelligent', 'Chaotic evil', 'L (4'' at shoulder)', 'Nil', 'Nil', NULL, NULL, NULL, 'Chimera.png', 'images/monsters/Chimera.png', 'A chimera is a composite monster combining three creatures: the hindquarters of a giant goat, the foreparts of a lion, and the wings and head of a dragon. It has three heads—goat, lion, and dragon—each capable of attack. It strikes with its fore claws, gores with its goat horns, bites with its lion head, and uses its dragon head as an additional biting attack. The dragon head can, with a 50% chance, breathe fire in a 5" range causing 3–24 damage (saving throw applies). Chimerae are vicious and unpredictable, using all attacks in close combat and their breath weapon when advantageous. They can speak a very limited form of red dragon language. The goat portions are black with amber eyes and yellowish horns; the lion parts are tawny with a dark mane, green eyes, and red maw; the dragon wings are brownish-black, with an orange dragon head and black eyes and mouth.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (15, 'Giant Crayfish', NULL, 'Uncommon', '1-4', '4', '6"/12"', '4+4', 'Nil', 'Nil', '2', '2-12/2-12', 'surprise on 1-3; ambush from hiding', 'Nil', 'Standard', 'Non-', 'Neutral', 'L (8''+ long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Crayfish.png', 'images/monsters/Giant_Crayfish.png', 'Giant crayfish are aquatic monsters found only in fresh water. They move slowly on land but can swim rapidly for short bursts. Like giant crabs, they lie concealed and rush out to seize prey, gaining surprise on a 1–3 on a six-sided die. They attack with two powerful claws capable of crushing damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (16, 'Crocodile', NULL, 'Common', '3-24', '5', '6"/12"', '3', 'Nil', 'Nil', '2', '2-8/1-12', 'surprise on 1-3; ambush from concealment', 'Nil', 'Standard', 'Animal', 'Neutral', 'L (8''-15'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Crocodile.png', 'images/monsters/Crocodile.png', 'Crocodiles are large aquatic reptiles typically found in rivers and swamps. They are voracious and unintelligent predators that lie concealed near the water’s edge to ambush prey, gaining surprise on a 1–3 on a six-sided die. They attack with powerful jaws and dragging bites. In cold weather they become sluggish, reducing their movement by half.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (17, 'Giant Crocodile', NULL, 'Very rare to common', '1 or 2-12', '4', '6"/12"', '7', 'Nil', 'Nil', '2', '3-18/2-20', 'surprise on 1-3; ambush from concealment', 'Nil', 'Standard', 'Animal', 'Neutral', 'L (21''-30'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Crocodile.png', 'images/monsters/Giant_Crocodile.png', 'Giant crocodiles are massive versions of normal crocodiles, often found in saltwater or prehistoric environments. Like their smaller kin, they are stupid and voracious predators that rely on concealment to ambush prey, gaining surprise on a 1–3 on a six-sided die. They attack with crushing jaws capable of inflicting severe damage. Cold weather slows them significantly, reducing movement by half.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (18, 'Giant Crab', NULL, 'Rare', '2-12', '3', '9"', '3', 'Nil', 'Nil', '2', '2-8/2-8', 'surprise on 1-4; ambush from concealment', 'Nil', 'Standard', 'Non-', 'Neutral', 'L (4''+ diameter)', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Crab.png', 'images/monsters/Giant_Crab.png', 'Giant crabs are found near water of all types and function equally well on land or in water. They constantly seek food and will hide before rushing out to seize prey, gaining surprise on a 1–4 on a six-sided die. Their eyes are mounted on stalks, allowing them to peer over ledges and around corners while remaining concealed. They attack with two powerful claws capable of crushing damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (19, 'Djinni', NULL, 'Very rare', '1', '4', '9"/24"', '7+3', 'Nil', 'Nil', '1', '2-16', 'spell-like abilities; whirlwind; invisibility; gaseous form; illusion; creation of matter', '-1 to hit and damage from air-based creatures', 'Standard', 'Average to high', 'Chaotic good', 'L (10.5'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Djinni.png', 'images/monsters/Djinni.png', 'Djinn are powerful beings from the elemental plane of air. Each can use a variety of magical abilities once per day, including creating food and drink for 2–12 persons, creating soft goods or wooden items permanently, creating temporary metal objects, and generating complex illusions with both visual and auditory components. They may also become invisible, assume gaseous form, wind walk, or form a whirlwind. The whirlwind takes one round to form and one to dissipate, lasts one melee round, and causes 2–12 damage while sweeping away creatures and destroying those under 2 hit dice. Djinn can carry up to 6,000 gold pieces weight indefinitely and up to double that for short durations before requiring rest. They can communicate with any intelligent creature through limited telepathy, and they travel between elemental, astral, and material planes. Djinn society is ruled by a caliph with nobles and officials beneath him.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (20, 'Dog (War)', NULL, 'Uncommon', '—', '6', '12"', '2+2', 'Nil', 'Nil', '1', '2-8', 'trained attack', 'Nil', 'Standard', 'Semi-', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Dog_War.png', 'images/monsters/Dog_War.png', 'War dogs are large, trained animals used for combat. They are loyal to their handlers and highly aggressive in battle. Typically equipped with studded leather armor and spiked collars, they are conditioned to attack on command and fight until disabled. The number encountered depends on their masters.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (21, 'Dog (Wild)', NULL, 'Common', '4-16', '7', '15"', '1+1', 'Nil', 'Nil', '1', '1-4', 'pack tactics', 'Nil', 'Standard', 'Semi-', 'Neutral', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Dog_Wild.png', 'images/monsters/Dog_Wild.png', 'Wild dogs roam in packs across many regions, sometimes overlapping with wolf territories. They typically avoid conflict if well-fed but can become dangerous when hungry or threatened. Wild dogs rely on pack behavior to harass and wear down prey. They can be tamed only if separated from their pack.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (22, 'Black Dragon', NULL, 'Uncommon', '1-4', '3', '12"/24"', '6-8', '30%', 'H', '3', '1-4/1-4/3-18', 'acid breath weapon (line); possible spell use by age', 'Nil', 'Standard', 'Average', 'Chaotic evil', 'L (30'' long)', 'Nil', 'Nil', '30%', '10%', '50%', 'Black_Dragon.png', 'images/monsters/Black_Dragon.png', 'Black dragons are evil reptiles typically found in foul swamps, marshes, or deep subterranean caves. They prefer dark, isolated lairs and exhibit a cruel, cunning disposition. In combat they attack with two claws and a bite or use their breath weapon, which is a narrow line of acid projected outward from the dragon’s head. The acid stream is directional and extends in a straight line, striking targets in its path. Black dragons capable of speech may also employ magic, gaining one first-level spell per age category (1–8 spells total), each usable once per day. Their spells require only verbal components and may include duplicates depending on random determination.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (23, 'Blue Dragon', NULL, 'Rare', '1-4', '2', '9"/24"', '8-10', '50%', 'H, S', '3', '1-6/1-6/3-24', 'lightning breath weapon (line); spellcasting by age', 'Nil', 'Standard', 'Very', 'Lawful evil', 'L (42'' long)', 'Nil', 'Nil', '60%', '30%', '30%', 'Blue_Dragon.png', 'images/monsters/Blue_Dragon.png', 'Blue dragons inhabit deserts and arid regions, typically lairing in vast underground caverns. They attack with claw/claw/bite or by using their breath weapon, which is a bolt of lightning projected in a straight line approximately 1/2" wide and 10" long. This discharge maintains a consistent shape and direction. Blue dragons capable of speech may also use spells, with spellcasting increasing by age: early maturity grants first-level spells, mid stages grant second-level spells, and the oldest dragons gain third-level spells. An ancient blue dragon may possess multiple spells of varying levels, each usable once per day unless duplicates are rolled. Blue dragons are intelligent, calculating, and highly territorial predators suited to open, dry environments.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (24, 'Brass Dragon', NULL, 'Uncommon', '1-4', '2', '12"/24"', '6-8', '25%', 'H', '3', '1-4/1-4/4-16', 'sleep gas cone; fear gas cloud; spellcasting by age', 'Nil', 'Standard', 'High', 'Chaotic good (neutral tendencies)', 'L (30'' long)', 'Nil', 'Nil', '30%', '30%', '50%', 'Brass_Dragon.png', 'images/monsters/Brass_Dragon.png', 'Brass dragons inhabit sandy deserts and arid regions, lairing in large underground caverns. They are talkative, curious, and often seek conversation, though they can be self-centered and tend toward neutrality in behavior. In combat they attack with claw/claw/bite or use one of two breath weapons. The first is a cone of sleep gas extending outward and widening to affect targets at range. The second is a cloud of fear gas that expands in a billowing formation above the ground, causing creatures to flee in terror. Creatures affected by either gas must save versus dragon breath or fall asleep or flee in fear. Save modifiers depend on dragon size, with smaller dragons easier to resist and larger dragons more difficult. Brass dragons that can speak may use spells, gaining one first-level spell at each odd-numbered age stage and one second-level spell at each even-numbered stage. All spells are determined randomly.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (25, 'Bronze Dragon', NULL, 'Rare', '1-4', '0', '9"/24"', '8-10', '45%', 'H, S, T', '3', '1-6/1-6/4-24', 'lightning breath (line); repulsion gas cloud; spellcasting by age', 'Nil', 'Standard', 'Exceptional', 'Lawful good', 'L (42'' long)', 'Nil', 'Nil', '60%', '60%', '25%', 'Bronze_Dragon.png', 'images/monsters/Bronze_Dragon.png', 'Bronze dragons dwell in subterranean lairs near large bodies of water such as lakes and seas. Though they value treasure, they are fundamentally benevolent and often take the form of animals to observe human activity. In combat they attack with claw/claw/bite or employ one of two breath weapons. The first is a bolt of lightning projected in a straight line approximately 1/2" wide and 10" long. The second is a repulsion gas cloud that expands in a three-dimensional volume, forcing affected creatures to move away from the dragon for several rounds unless a saving throw versus dragon breath is successful. Bronze dragons capable of speech may use spells, gaining first-level spells at early growth stages, second-level spells at mid stages, third-level spells at later stages, and additional fourth-level spells at the oldest stages. An ancient bronze dragon may possess multiple spells across these levels, all determined randomly.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (26, 'Gold Dragon', NULL, 'Very rare', '1-3', '-2', '12"/30"', '10-12', '65%', 'H, R, S, T', '3', '1-8/1-8/6-36', 'fire breath (cone); chlorine gas cloud; high-level spellcasting; polymorph self', 'Nil', 'Standard', 'Genius', 'Lawful good', 'L (54'' long)', 'Nil', 'Nil', '90%', '100%', '10%', 'Gold_Dragon.png', 'images/monsters/Gold_Dragon.png', 'Gold dragons are the most powerful and noble of the common dragon species, capable of dwelling in any climate but always lairing in solid stone structures such as caves or castles. They are lawful, just, and benevolent, though they prize treasure and even consume precious metals and gems. They frequently assume alternate forms, including animals or humanoids, using polymorph abilities to interact with the world unseen. In combat they attack with claw/claw/bite or employ one of two breath weapons: a cone of fire approximately 9" long and 3" wide, or a chlorine gas cloud roughly 5" by 4" by 3" in volume. Gold dragons possess the most advanced spellcasting of dragonkind, gaining spells from 1st through 6th level as they age, with additional spells at each stage of maturity. At the highest ages they can cast multiple spells of each level and may also polymorph themselves several times per day. Their intelligence is exceptional, and many maintain spellbooks, ensuring access to a wide range of powerful magic.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (27, 'Green Dragon', NULL, 'Rare', '1-4', '2', '9"/24"', '7-9', '40%', 'H', '3', '1-6/1-6/2-20', 'chlorine gas cloud breath; spellcasting by age', 'Nil', 'Standard', 'Average to very', 'Lawful evil', 'L (36'' long)', 'Nil', 'Nil', '45%', '20%', '40%', 'Green_Dragon.png', 'images/monsters/Green_Dragon.png', 'Green dragons prefer to establish underground lairs in or near forests, especially in darker and more forbidding regions. They are ill-tempered, cunning, and thoroughly evil. In combat they attack with claw/claw/bite or employ their breath weapon, which is a cloud of poisonous chlorine gas expanding roughly 5" long, 4" wide, and 3" high. Green dragons capable of speech may also use magic, gaining one first-level spell at each of their first four age stages, and one second-level spell at each subsequent stage, to a maximum of four first-level and four second-level spells. All spells are determined randomly.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (28, 'Silver Dragon', NULL, 'Very rare', '1-4', '-1', '9"/24"', '9-11', '55%', 'H, T', '3', '1-6/1-6/5-30', 'cone of cold breath; paralytic gas cloud; spellcasting by age; polymorph', 'Nil', 'Standard', 'Exceptional', 'Lawful good', 'L (48'' long)', 'Nil', 'Nil', '75%', '75%', '15%', 'Silver_Dragon.png', 'images/monsters/Silver_Dragon.png', 'Silver dragons dwell in high mountainous regions, clouds, and similar lofty places. They are noble, benevolent creatures akin to gold dragons and can polymorph into human or animal forms, often appearing as kindly figures. In combat they attack with claw/claw/bite or employ one of two breath weapons: a cone of cold approximately 8" long with a 3" base, or a cloud of paralytic gas roughly 5" long, 4" wide, and 2" high. Creatures within the gas must save or be paralyzed. Spell-using silver dragons may employ up to ten spells, gaining 1st and 2nd level spells early, then progressing to 3rd level at sub-adult/young adult, 4th level at adult/old, and 5th level at very old/ancient stages. About 25% possess spell books, allowing more flexible spell selection.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (29, 'White Dragon', NULL, 'Uncommon', '1-4', '3', '12"/30"', '5-7', '20%', 'E, O, S', '3', '1-4/1-4/2-16', 'cone of cold breath; limited spellcasting (rare)', 'Nil', 'Standard', 'Average (low)', 'Chaotic evil', 'L (24'' long)', 'Nil', 'Nil', '20%', '5%', '60%', 'White_Dragon.png', 'images/monsters/White_Dragon.png', 'White dragons inhabit cold climates such as icy caves and deep frozen regions. They are the least intelligent of the true dragons but remain vicious and greedy. In combat they attack with claw/claw/bite or breathe a cone of cold approximately 7" long with a base diameter of about 2.5". Rare individuals can cast magic, gaining up to four first-level spells total, acquired at even-numbered age stages (young, young adult, old, ancient). Duplicate spell rolls indicate multiple daily uses of the same spell.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (30, 'Dwarf', NULL, 'Common', '40-400', '4', '6"', '1', '50%', 'Individuals M (x5); G, Q (x20), R', '1', 'By weapon or 1-8', 'Variable by class; multi-class capability', 'Saving throws at +4 levels higher', 'As above', 'Very', 'Lawful good', 'S (4''+ tall)', 'Nil', 'Nil', '75%', 'N/A', 'N/A', 'Dwarf.png', 'images/monsters/Dwarf.png', 'Dwarves dwell in rocky hills and underground complexes, typically organized into competitive but cooperative clans. They are capable of multi-classing (fighter/clerics, for example) with varying proficiency between classes. For every 40 dwarves there is a 2nd–6th level fighter; larger groups include progressively higher-level fighters and fighter/clerics, along with females and young in lairs. Dwarves speak their own tongue plus gnome, goblin, kobold, and orc; 75% also speak common. They are sturdy, stocky humanoids with deep tan to light brown skin, often with brown, black, or gray hair, and favor earth-toned clothing. Though short, they weigh at least 150 pounds and commonly live 350+ years. Mountain dwarves are slightly larger, use fewer crossbows and more spears, and can reach higher levels with exceptional strength.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (31, 'Dryad', NULL, 'Very rare', '1-6', '9', '12"', '2', '10%', 'M (x100), Q (x10)', '1', 'Dagger', 'Charm person (up to 3/day, -3 save)', 'Tree merging; dimension door to bound tree', '50%', 'High', 'Neutral', 'M', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Dryad.png', 'images/monsters/Dryad.png', 'Dryads are beautiful tree spirits found only near oak trees, never more than 36" from their bonded tree. They are shy and non-violent, able to vanish by stepping into trees and traveling unseen to their own. If threatened or encountering a male with 16+ charisma, a dryad may cast charm person up to three times per day (once per round) with a -3 penalty to the victim’s saving throw. Victims taken away have a 50% chance of never returning, or may return after 1-4 years. Dryads speak their own tongue, elven, pixieish, sprite, and can speak with plants. They possess perfect knowledge of their forest and may aid those who approach peacefully.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (32, 'Giant Eagle', NULL, 'Rare', '1-20', '7', '3"/48"', '4', '20%', 'Q, C (magic only)', '3', '1-6/1-6/2-12', 'Diving attack: +4 to hit, double claw damage (no beak)', 'Exceptional vision; rarely surprised', 'Standard', 'Average', 'Neutral', 'M (20'' wingspan)', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Giant_Eagle.png', 'images/monsters/Giant_Eagle.png', 'Giant eagles inhabit high cliffs, mountains, and mesas. Their eyesight is so keen they are almost never surprised except in their lair or at night. When diving from 50+ feet they gain +4 to hit and deal double claw damage (2-12/2-12) but do not use their beak. They can carry up to 2000 gold pieces at half speed. Outside their lair they ignore good creatures but attack evil ones that appear threatening. They are friendly with certain dwarves and elves, have their own language, and can communicate via limited telepathy. In lairs they are always hostile, especially if young or eggs are present. They can be tamed.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (33, 'Efreeti', NULL, 'Very rare', '1', '2', '9"/24"', '10', 'Nil', 'Nil', '1', '3-24', 'Wish (3 total if enslaved); invisibility; gaseous form; detect magic; enlarge; polymorph self; illusion; wall of fire; pyrotechnics', 'Immune to normal fire; magical fire at -1 to hit and damage', 'Standard', 'Very', 'Neutral (tends lawful evil)', 'L (12'' tall)', 'Nil', 'Nil', 'Telepathic', 'N/A', 'N/A', 'Efreeti.png', 'images/monsters/Efreeti.png', 'Efreet are powerful beings from the Elemental Plane of Fire and enemies of the djinn. They will attack djinn on sight and resent servitude, often twisting commands maliciously. An efreeti can be compelled to serve for up to 1,000 days or until granting three wishes. Once per day it may become invisible, assume gaseous form, detect magic, enlarge, polymorph itself, create persistent illusions, or conjure a wall of fire. It may also produce flame or pyrotechnics at will. Normal fire does not harm efreet, and magical fire attacks suffer a -1 penalty to hit and damage. Efreet can carry up to 7,500 gold pieces without strain and travel across material, elemental, and astral planes. They communicate with intelligent beings via limited telepathy. Their society is centered in the City of Brass, ruled by a powerful Sultan and structured with nobles such as pashas, emirs, and viziers.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (34, 'Air Elemental', NULL, 'Very rare', '1', '2', '36"', '8 / 12 / 16', 'Nil', 'Nil', '1', '2-20', 'Whirlwind form (kills <3 HD; damages others 2-16)', '+2 or better weapon to hit', 'Standard', 'Low', 'Neutral', 'L', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Air_Elemental.png', 'images/monsters/Air_Elemental.png', 'Air elementals move by flight and may slow their movement as desired. In aerial combat they gain +1 to hit and +2 damage per die. They can form a whirlwind (height = HD in feet; 8–16 ft) which lasts 1 melee round, killing creatures under 3 HD and dealing 2–16 damage to others. Formation and dissipation each require one full turn. If space restricts full height, effectiveness is halved. More powerful and intelligent air elementals exist on their home plane.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (35, 'Earth Elemental', NULL, 'Very rare', '1', '2', '6"', '8 / 12 / 16', 'Nil', 'Nil', '1', '4-32', 'Double damage vs ground-bound; structural battering', '+2 or better weapon to hit', 'Standard', 'Low', 'Neutral', 'L', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Earth_Elemental.png', 'images/monsters/Earth_Elemental.png', 'Earth elementals move slowly and must travel through the ground to cross water. They deal full damage to creatures touching the earth and -2 per die vs airborne targets. Against stone or earth structures they act as a battering ram (2–8 structural damage). Summoned from earth or stone. Extremely powerful specimens exist on their home plane.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (36, 'Fire Elemental', NULL, 'Very rare', '1', '2', '12"', '8 / 12 / 16', 'Nil', 'Nil', '1', '3-24', 'Ignites flammable materials', '+2 or better weapon to hit', 'Standard', 'Low', 'Neutral', 'L', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Fire_Elemental.png', 'images/monsters/Fire_Elemental.png', 'Fire elementals ignite combustible materials on contact. They suffer -1 per damage die against fire-using opponents and cannot cross non-flammable liquids. Native to the plane of fire, where stronger and more varied forms exist under a powerful ruler.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (37, 'Water Elemental', NULL, 'Very rare', '1', '2', '6" / "18"', '8 / 12 / 16', 'Nil', 'Nil', '1', '5-30', 'Capsizes or stops vessels; stronger in water', '+2 or better weapon to hit', 'Standard', 'Low', 'Neutral', 'L', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Water_Elemental.png', 'images/monsters/Water_Elemental.png', 'Water elementals must remain within 6" of their source and require large volumes of liquid to form. Outside water they lose 1 damage per die; within water they act at full strength, move faster, and can overturn or halt ships (1 ton per hit die). More powerful and intelligent water beings exist on their home plane.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (38, 'Elf', NULL, 'Uncommon', '20-200', '5', '12"', '1 + 1', '10%', 'Individuals N; G, S, T in lair', '1', 'By weapon or 1-10', '+1 with normal bow or sword', '90% resistant to charm and sleep; surprise on 1-4 in natural surroundings; concealment/invisibility in vegetation', '90% to charm and sleep only', 'High and up', 'Chaotic good', 'M (5''+ tall)', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Elf.png', 'images/monsters/Elf.png', 'Elves may operate in two or more classes simultaneously and live in loose social structures under overlords. Larger bands contain progressively stronger fighters and magic-users, with additional leaders and retainers in lairs. They prefer secluded forests and often keep giant eagles as guards. Weapon distribution varies, but most wear mail and carry shields. In natural surroundings elves move silently, surprise on 1–4, and can blend into vegetation so as to be invisible while not attacking. They may move, fire bows, and move back in the same round. Elves have infravision to 60'', frequently detect secret doors, and speak many languages. They are slim, pale, dark-haired, green-eyed folk with long lives. Numerous subtypes exist, including aquatic, gray, wood, and half-elves.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (39, 'Ettin', NULL, 'Very rare', '1-4', '3', '12"', '10', '20%', 'Individual O, C, Y in lair', '2', '2-16/3-18', 'Dual independent attacks (one per head/arm)', 'Surprised only on a 1', 'Standard', 'Low', 'Chaotic evil', 'L (13''+ tall)', 'Nil', 'Nil', 'N/A', 'N/A', 'N/A', 'Ettin.png', 'images/monsters/Ettin.png', 'Ettins are two-headed, nocturnal giants that dwell in remote underground areas. Each head controls one arm, allowing them to attack twice per round. One head is almost always alert, making them difficult to surprise. They are closely related to orcs, wear filthy animal skins, and favor crude weapons such as spiked clubs.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (40, 'Giant Frog', NULL, 'Uncommon', '5-40', '7', '3"/9"', '1-3', 'Nil', 'Nil', '1', '1-3/1-6/2-8', 'Tongue attack (+4 to hit, pulls prey), swallow whole, leap attack (18" range)', 'Nil', 'Standard', 'Non-', 'Neutral', 'S to M (2''-6'')', 'Nil', 'Nil', NULL, NULL, NULL, 'Giant_Frog.png', 'images/monsters/Giant_Frog.png', 'Giant frogs inhabit marshes, swamps, and waterways. They attack with a long sticky tongue (3× body length) to pull prey into their mouths. Creatures struck are dragged in and take maximum damage unless they resist. They can leap up to 18" horizontally and 30'' vertically. Small humanoids may be swallowed whole, with chances to cut free. They surprise on 1–4 and fear fire.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (41, 'Killer Frog', NULL, 'Very rare', '3-18', '8', '6"/12"', '1-4', 'Nil', 'Nil', '3', '1-2/1-2/2-5', 'Bite and claw attacks; aggressive behavior', 'Nil', 'Standard', 'Non-', 'Neutral', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Killer_Frog.png', 'images/monsters/Killer_Frog.png', 'Killer frogs are a smaller, more aggressive offshoot of giant frogs. They attack with claws and teeth rather than relying on tongue capture. They are man-eaters and often the result of selective or unnatural breeding.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (42, 'Poisonous Frog', NULL, 'Rare', '2-12', '8', '3"/9"', '1', 'Nil', 'Nil', '1', '1', 'Poison skin and bite (save at +4)', 'Nil', 'Standard', 'Non-', 'Neutral', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Poisonous_Frog.png', 'images/monsters/Poisonous_Frog.png', 'Poisonous frogs secrete a toxin through their skin, making both contact and bites dangerous. The poison is relatively weak, granting victims a +4 bonus on saving throws. Otherwise similar in behavior to normal frogs.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (43, 'Gas Spore', NULL, 'Rare', '1-3', '9', '3"', '1 hit point', 'Nil', 'Nil', '1', 'Explosion (6-36 in 20'' radius)', 'Explodes if struck; infection on contact (fatal unless cured in 24h)', 'Deceptive appearance (mistaken for beholder)', 'Standard', 'Non-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Gas_Spore.png', 'images/monsters/Gas_Spore.png', 'Gas spores resemble beholders at a distance (90% chance beyond 10''). If damaged they explode, dealing 6–36 damage in a 20'' radius (save halves). Contact causes lethal infection—victims must receive cure disease within 24 hours or die and sprout 2–8 new gas spores.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (44, 'Gargoyle', NULL, 'Uncommon', '2-16', '5', '9"/15"', '4 + 4', '20%', 'Individuals M (x10), C in lair', '4', '1-3/1-3/1-6/1-4', 'Nil', '+1 or better weapon to hit', 'Standard', 'Low', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Gargoyle.png', 'images/monsters/Gargoyle.png', 'Gargoyles are winged, stone-like creatures that attack with claws, bite, and horn. They are immune to non-magical weapons (+1 or better required to hit). Often found perched like statues, they ambush prey and inhabit ruins or high stone structures.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (45, 'Ghost', NULL, 'Very rare', '1', '0 (or 8 ethereal)', '9"', '10', '25%', 'E, S', '1', 'Age 10-40 years', 'Aging touch; fear on sight (ages 10 years + flee); magic jar attack', 'Non-corporeal; hit only by silver (half damage) or magic; ethereal combat rules', 'Special', 'High', 'Lawful evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Ghost.png', 'images/monsters/Ghost.png', 'Ghosts are non-corporeal undead spirits. Viewing one causes humanoids to age 10 years and flee unless they save. They attack by magic jar or by touch (aging 10–40 years). Normally only affectable on the ethereal plane; when semi-material they can be struck by silver (half damage) or magic weapons. Victims slain by ghosts cannot be raised.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (46, 'Ghast', NULL, 'Rare', '1-6', '4', '15"', '4', '10%', 'B, Q, R, S, T', '3', '1-4/1-4/1-8', 'Paralysis (affects elves); stench (10'' radius, -2 to hit if failed save)', 'Undead immunities; cold iron double damage; turnable by clerics', 'Standard', 'Very', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Ghast.png', 'images/monsters/Ghast.png', 'Ghasts are stronger, more intelligent variants of ghouls. They emit a foul stench causing nausea unless a save vs poison is made (-2 to hit if failed). Their attacks paralyze victims, including elves. As undead, they are immune to sleep and charm, take double damage from cold iron, and may be turned by clerics.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (47, 'Ghoul', NULL, 'Uncommon', '2-24', '6', '9"', '2', '20%', 'B, T', '3', '1-3/1-3/1-6', 'Paralysis (humanoids except elves); victims killed become ghouls', 'Immune to sleep and charm; turned by clerics; protection from evil wards them', 'Standard', 'Low', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Ghoul.png', 'images/monsters/Ghoul.png', 'Ghouls are undead humanoids that feed on corpses. Their claw and bite attacks paralyze humans, dwarves, gnomes, half-elves, and halflings unless a save vs paralysis is made; elves are immune. Any human slain by a ghoul becomes a ghoul unless properly blessed or resurrected. Ghouls attack fearlessly in packs. They are immune to sleep and charm spells, can be turned by clerics, and are completely warded off by a protection from evil spell.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (48, 'Cloud Giant', NULL, 'Rare', '1-6', '2', '15"', '12 + 2-7', '40%', 'E, Q (x5)', '1', '6-36', 'Hurl rocks (2-24 damage, 1–24 range); 60% chance to catch missiles', 'Surprised only on 1', 'Standard', 'Average to very', 'Neutral (good 50%, evil 50%)', 'L (18'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Cloud_Giant.png', 'images/monsters/Cloud_Giant.png', 'Unlike the commoner giants, cloud giants usually reside in crude castles built atop mountains or on magical cloud islands. In their lairs they may keep spotted lions as pets or guards. Groups may include giantesses and young. Adult cloud giants hurl rocks from 1" to 24" for 2–24 damage and catch missiles 60% of the time. Ten percent are very intelligent; these dwell on cloud islands and can levitate themselves and up to 20,000 gp twice per day. Evil cloud giants may keep captives as slaves. Their skin ranges from pale blue-white to light blue, with silver-white or brass hair, and they wield great clubs.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (49, 'Fire Giant', NULL, 'Uncommon', '1-8', '3', '12"', '11 + 2-5', '35%', 'E', '1', '5-30', 'Hurl rocks (2-20 damage, 1–20 range)', 'Impervious to fire', 'Standard', 'Average to low', 'Lawful evil', 'L (12'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Fire_Giant.png', 'images/monsters/Fire_Giant.png', 'Fire giants are broad, dark-skinned giants found in castles or caverns. In lairs they may keep 1–4 large hell hounds as watchdogs; larger groups include females and young. Adult fire giants hurl rocks from 1" to 20" distances, inflicting 2–20 damage. They can catch missiles 50% of the time. They are completely impervious to fire, even red dragon breath. Their skin is coal black, hair flaming red or orange, eyes deep red, and they wear armor or dragon hides while favoring huge swords.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (50, 'Frost Giant', NULL, 'Rare', '1-8', '4', '12"', '10 + 1-4', '30%', 'E', '1', '4-24', 'Hurl rocks (2-20 damage, 1–20 range)', 'Impervious to cold', 'Standard', 'Average to low', 'Chaotic evil', 'L (15'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Frost_Giant.png', 'images/monsters/Frost_Giant.png', 'Frost giants more commonly inhabit castles, though they often lair in large frigid caverns. There is a 50% probability that they will have 1-6 winter wolves in their lair as watchdogs. If more than 4 frost giants are encountered in their lair numbers 5 and 6 will be females, and 7 and 8 will be young giants. Adult frost giants are able to hurl rocks from 1" to 20" distances, inflicting 2-20 hit points of damage. They can catch like missiles 40% of the time. Frost giants are impervious to cold, even white dragon breath. Frost giants have dead white or ivory skin, blue-white or yellow hair, and pale blue or yellow eyes. They wear armor and bear arms similar to those of northern barbarians.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (51, 'Hill Giant', NULL, 'Common', '2-12', '4', '12"', '8 + 1-2', '25%', 'D', '1', '2-16', 'Hurl rocks (2-16 damage)', 'None (standard giant surprise rules)', 'Standard', 'Low', 'Chaotic evil', 'L (10.5'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Hill_Giant.png', 'images/monsters/Hill_Giant.png', 'Hill giants are the smallest and most common of giant-kind, but still extremely strong. They hurl rocks as missile weapons and are known for crude, brutal behavior. They often dwell in hills or caves and may keep dire wolves or similar creatures as guards. Fifty percent or more may speak ogre. They are gluttonous, dim-witted, and destructive.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (52, 'Stone Giant', NULL, 'Uncommon', '1-8', '0', '12"', '9 + 1-3', '30%', 'D', '1', '3-18', 'Hurl rocks (3-30 damage, 1–30 range)', '90% chance to catch thrown missiles', 'Standard', 'Average', 'Neutral', 'L (12'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Stone_Giant.png', 'images/monsters/Stone_Giant.png', 'Stone giants dwell in mountainous caves and caverns. Seventy-five percent have 1-4 cave bears guarding their lairs. Larger groups include females and young. They enjoy hurling rocks at long range and are extremely adept at catching missiles. Their gray coloration allows them to blend into rocky terrain, enhanced by rock-colored garments. They are sometimes playful, especially at night, and typically wield stone weapons.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (53, 'Storm Giant', NULL, 'Rare', '1-4', '1', '15"', '15 + 2-7', '55%', 'E, Q (x10), S', '1', '7-42', 'Lightning bolt (8d8, 1/day); spell use (predict weather, call lightning, control winds, weather summoning)', 'Immune to electricity; levitation 2/day; underwater breathing', 'Standard', 'Exceptional', 'Chaotic good', 'L (21'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Storm_Giant.png', 'images/monsters/Storm_Giant.png', 'Storm giants are the most powerful true giants, living in remote places such as cloud islands, mountain peaks, or underwater realms. Their lairs may include rocs, griffons, or sea lions depending on habitat. Unlike other giants they do not hurl rocks, instead using lightning bolts and weather magic. They can levitate and breathe underwater. Storm giants are not harmed by electrical energy, including blue dragon breath. Their coloration ranges from pale green (marine forms) to violet hues.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (54, 'Gnome', NULL, 'Rare', '40-400', '5', '6"', '1', '50%', 'Individuals M (x3); C, Q (x20) in lair', '1', 'By weapon or 1-6', 'For every 40 gnomes encountered there will be a fighter of 2nd, 3rd, or 4th level; if 160 or more are in a group there will be an additional 5th level fighter and one 3rd level fighter as chief and lieutenant; if 200 or more are encountered they will also have a gnomish cleric of 4th, 5th, or 6th level; if 320 or more are encountered there will also be a 6th level fighter, two 5th level fighters, a 7th level cleric, and four 3rd level clerics; +1 to hit kobolds and goblins; gnolls, bugbears, ogres, trolls, and giants suffer -4 to hit gnomes in melee', 'Save at 4 levels higher; see in the dark (infravision) to 60''', 'As above', 'Very', 'Neutral to lawful good', 'S (3''+ tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Gnome.png', 'images/monsters/Gnome.png', 'Gnomes have a social organization based on clans, similar to dwarves, and these groups are neither exclusive nor hostile to each other, although rivalries exist. For every 40 gnomes encountered there will be a fighter of 2nd, 3rd, or 4th level (die roll 1-2, 3-4, or 5-6). If 160 or more gnomes are in a group there will be an additional 5th level fighter and one 3rd level fighter as chief and lieutenant. If 200 or more are encountered they will also have a gnomish cleric of 4th, 5th, or 6th level in addition to the others. If 320 or more gnomes are encountered there will also be a 6th level fighter, two 5th level fighters, a 7th level cleric, and four 3rd level clerics. If encountered in their lair (home) there will be the following additional gnomes: 2-8 fighters of 2nd or 3rd level, 1-4 clerics of 2nd level, and females and young equal to 50% and 25% respectively of the number of adult males. A gnomish lair is sometimes based upon earthen burrows, although 75% of the time it will be made in rocky hill formations. Gnomes are typically armored with leather armor which is ringed or well studded with metal and shield (armor class 5). Their typical weaponing is: short sword and short bow 10%, short sword and spear 20%, club and sling 15%, club and spear 40%, and club and short sword 15%. All gnomes above normal level will have chainmail and shield. Those above 5th level will have plate armor and shield. Higher level fighters will have a 10% chance per level of having magic armor and/or weapons. Gnomish clerics will likewise have a 10% chance per level for 1-3 additional items (potion, clerical scroll, ring, wand/staff/rod, miscellaneous magic usable by clerics). Gnomes are 80% likely to have tamed animals to serve as guards in their lair: 5-30 badgers (70%) or 3-12 giant badgers (20%) or 2-8 wolverines (10%). Due to their great hatred of kobolds and goblins, all gnomes gain a bonus of +1 on their dice rolls to hit these opponents. When gnomes are in melee with gnolls, bugbears, ogres, trolls, or giants their opponents must deduct 4 from their dice rolls to hit the gnomes because of their small size and their combat skill against these much bigger creatures. All gnomes are highly resistant to magic and poison, so they make saving throws at 4 levels above their actual level. Gnomes can see in the dark (infravision), noting monsters at 60''. Because of their mining skills gnomes are excellent (50% to 80% likely) in detection of passages which slope upwards or downwards, unsafe walls, floors, and ceilings, and approximate depth and direction. It is rumored that there exist gnomes with magical abilities up to 4th level, but this has not been proved. Besides their alignment and racial tongues, gnomes speak kobold, goblin, halflingish, dwarvish, and can speak with burrowing mammals as well. Most gnomes are wood brown, a few range to gray brown, of skin. Their hair is medium to pure white, and their eyes are gray-blue to bright blue. They wear leather and earth tones of cloth and like jewelry. The average gnome will live for 600 years.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (55, 'Goblin', NULL, 'Uncommon', '40-400', '6', '6"', '1-7 Hit points', '40%', 'Individuals K; Lair C', '1', '1-6 or by weapon', 'For every 40 goblins encountered there will be a leader and 4 assistants equal to orcs, each having 7 hit points and attacking as monsters with a full hit die; if 200 or more goblins are encountered there will also be a sub-chief and 2-8 guards, each fighting as hobgoblins and having 8 hit points, armor class 5, and doing 1-8 hit points damage; 25% chance any force encountered has 10% mounted on huge wolves with 10-40 huge wolves without riders; in lair there will be a goblin chief and 2-8 bodyguards with 9-14 hit points, armor class 4, fighting as gnolls and doing 2-8 damage', 'Nil', 'Standard', 'Average (low)', 'Lawful evil', 'S (4'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Goblin.png', 'images/monsters/Goblin.png', 'Goblins have a tribal society, the strongest ruling the rest, allowing fealty to the goblin king. It is possible that goblins are distantly related to kobolds. Like the latter, goblins enjoy dwelling in dismal surroundings, although they tend to inhabit caves and similar underground places in preference to any habitation above ground. They hate full daylight and attack at -1 when in sunlight. Goblins have normal infravision (60'' range). For every 40 goblins encountered there will be a leader and 4 assistants who are equal to orcs, each having 7 hit points and attacking as monsters with a full hit die. If 200 or more goblins are encountered there will be the following additional figures: a sub-chief and 2-8 guards, each fighting as hobgoblins and having 8 hit points, armor class 5, and doing 1-8 hit points damage. There is a 25% chance that any force of goblins encountered will have 10% of its strength mounted on huge wolves and if this is the case there will also be from 10-40 of these creatures without riders. In their lair there will be the following additional figures: a goblin chief and 2-8 bodyguards (9-14 hit points, armor class 4, fight as gnolls doing 2-8 hit points of damage), females and young equal to 60% and 100% respectively of the number of male goblins encountered. As is usual with creatures of this sort, the females and young do not fight. A goblin lair will be protected by from 5-30 huge wolves not less than 60% of the time. There is a 20% chance that 2-12 bugbears will be in a goblin lair. Typical weapons are short sword and military pick 10%, short sword and sling 10%, short sword and spear 10%, sling 10%, morning star 20%, military pick 10%, and spear 30%. Leaders and guards will typically have the best weapons, bearing two each. Goblins are fair miners, and they are able to note new or unusual construction 25% of the time. They hate gnomes and dwarves and will attack them in preference to any other creature. All goblins are slave takers and fond of torture. The languages spoken by goblins are their own, lawful evil, kobold, orcish, and hobgoblin. Goblins range from yellow through dull orange to brick red in skin color. Their eyes are reddish to lemon yellow. They dress in dark leather gear, and their garments tend towards dull, soiled-looking colors such as brown drab, dirty gray, and stained maroon. Goblins reach the age of 50 years or so.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (56, 'Clay Golem', NULL, 'Very rare', '1', '7', '7"', '50 Hit points', 'Nil', 'Nil', '1', '3-30', 'Each melee round the clay golem is in combat there is a 1% cumulative chance that it will be imbued with a chaotic evil spirit; if this happens it immediately passes from the control of the cleric and attacks any living thing, moving to the closest one to attack and proceeding on to the next after killing it; once per day after engaging in at least one round of combat the golem can be hasted for 3 melee rounds, striking twice per round during this period; if out of control, the golem will immediately haste itself if it has not previously done so', 'Damage inflicted upon living matter by a clay golem is only repairable by means of a healing spell from a cleric of 17th or greater level; clay golems can be struck only by blunt magical weapons such as hammers or maces; other weapons do not affect it; spells do not affect it except move earth drives the golem back 12" and inflicts 3-36 hit points of damage, disintegrate slows the golem 50% and inflicts 1-12 hit points of damage, and an earthquake cast directly at a clay golem stops it from moving that turn and inflicts 5-50 hit points of damage', 'See below', 'Non-', 'Neutral', 'L (8'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Clay_Golem.png', 'images/monsters/Clay_Golem.png', 'A clay golem can be created by a lawful good cleric of 17th or higher level unless a magical tome is used, in which case a lower level cleric can create one. It requires a resurrection spell, an animate objects spell, a commune spell, a prayer spell, and a bless spell. The cleric must first fashion a man-shaped clay statue, and once this is sculpted the cleric must go through an uninterrupted ritual using the required spells. Materials to do the spell require an outlay of 20,000 gold pieces. Vestments for the ritual cost another 30,000 gold pieces minimum. Once created the clay golem is under the command of the cleric who created it. Each melee round the clay golem is in combat there is a 1% cumulative chance that it will be imbued with a chaotic evil spirit. If this happens, the clay golem immediately passes from the control of the cleric and attacks any living thing, moving to the closest one to attack and proceeding on to the next after killing it. This behavior continues until the golem is destroyed, for control can never be regained. Damage inflicted upon living matter by a clay golem is only repairable by means of a healing spell from a cleric of 17th or greater level. Attacks by a clay golem are based on 11 hit dice. Once per day the golem can be hasted for 3 melee rounds after engaging in at least 1 round of combat. During this period it strikes twice per round. If out of control, the golem will immediately haste itself if it has not previously done so. Clay golems can be struck only by blunt magical weapons such as hammers or maces. Other weapons do not affect it. Spells do not affect it, except as follows: move earth will drive the golem back 12" and inflict 3-36 hit points of damage, disintegrate will slow the golem 50% and inflict 1-12 hit points of damage, and an earthquake cast directly at a clay golem will stop it from moving that turn and inflict 5-50 hit points of damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (57, 'Flesh Golem', NULL, 'Very rare', '1', '9', '8"', '40 Hit points', 'Nil', 'Nil', '2', '2-16/2-16', 'For each turn of melee a flesh golem engages in there is a 1% per melee round cumulative chance it will go berserk, attacking at random anything in sight; the monster''s master has a 10% per melee round chance of regaining control of the golem', 'Normal weapons do not harm flesh golems, but magical weapons have normal effect; spells of most sorts have no effect, but fire or cold based spells slow the golem 50% for 2-12 melee rounds; electrical attacks restore damage to the golem in direct relation to the number of dice of damage normally done', 'See below', 'Semi-', 'Neutral', 'L (7½'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Flesh_Golem.png', 'images/monsters/Flesh_Golem.png', 'A flesh golem can be created by means of a magical tome or by a high-level magic-user employing a wish spell, a polymorph any object, a geas, a protection from normal missiles, and a strength spell. In the latter case, the creator must be at least 14th level. The cost in materials is 1,000 gold pieces per hit point of the golem. It requires 1 month to fashion the creature. The creator of the flesh golem controls the monster and can have it follow simple commands such as go ahead, stop, or kill. The master of the golem can have it suspend its functioning until a set event takes place, such as someone entering its room. However, for each turn of melee a flesh golem engages in there is a 1% per melee round cumulative chance it will go berserk, attacking at random anything in sight. The monster''s master has a 10% per melee round chance of regaining control of the golem. The flesh golem is very powerful and able to smash through doors and wooden structures of normal construction. For example, a flesh golem would break through an oaken door with iron reinforcing bands and hinges in 5-8 melee rounds. It does 1 point of structural damage to wooden constructions every 3 melee rounds. Normal weapons do not harm flesh golems, but magical weapons have normal effect. Spells of most sorts have no effect on such monsters, but fire or cold based spells such as wall of fire, fire ball, and ice storm slow the golem 50% for 2-12 melee rounds. Electrical attacks restore damage to the golem in direct relation to the number of dice of damage normally done; for example, a 6 die lightning bolt restores 6 hit points of damage which the golem might have sustained.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (58, 'Stone Golem', NULL, 'Very rare', '1', '5', '6"', '60 Hit points', 'Nil', 'Nil', '1', '3-24', 'In addition to its normal attack, the stone golem is able to cast a slow spell on any opponent within 1" of its front facing every other melee round', 'Normal weapons do not harm stone golems; it requires weapons of +2 or greater enchantment to damage them; the only spells which affect a stone golem are rock to mud, which slows the golem 50% for 2-12 melee rounds, mud to rock, which restores all damage suffered by the golem, and stone to flesh, which makes the golem vulnerable to normal attacks on the following melee round', 'See below', 'Non-', 'Neutral', 'L (9½'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Stone_Golem.png', 'images/monsters/Stone_Golem.png', 'Stone golems of man-like shape are constructed by means of a magical tome or a magic-user of 16th or higher level employing the following spells: wish, polymorph any object, geas, and slow. The cost in materials is 1,000 gold pieces per hit point, and it requires 2 months construction time. Once created the stone golem can be controlled by its creator, and it will understand and obey simple commands such as attack, stop, wait, and go. The golem can be made to stand and wait to attack until someone does something to trigger it. In addition to its normal attack, the stone golem is able to cast a slow spell on any opponent within 1" of its front facing every other melee round. The strength of a stone golem is twice that of a flesh golem. It does 1 point of structural damage every other melee round. Normal weapons do not harm stone golems. In fact, it requires weapons of +2 or greater enchantment to damage them. The only spells which affect a stone golem are: rock to mud slows the golem 50% for 2-12 melee rounds, mud to rock restores all damage suffered by the golem, and stone to flesh makes the golem vulnerable to normal attacks on the following melee round.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (59, 'Iron Golem', NULL, 'Very rare', '1', '3', '6"', '80 Hit points', 'Nil', 'Nil', '1', '4-40', 'In addition to striking, an iron golem will breathe out a cloud of poisonous gas 1" x 1" x 1" directly before it once every 7 melee rounds', 'An iron golem can be struck only by magical weapons of +3 or greater enchantment; normal and magical weapons under +3 do no damage; the only magical attacks which affect the iron golem are electrical attacks such as a lightning bolt, which slows the monster 50% for 3 melee rounds; magical fire attacks repair damage on a hit point for hit point basis; iron golems are subject to attack from rust monsters', 'See below', 'Non-', 'Neutral', 'L (12'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Iron_Golem.png', 'images/monsters/Iron_Golem.png', 'Construction of an iron golem, bipedal and manlike, requires a magical tome or a magic-user of 18th or higher level employing the following spells: wish, polymorph any object, geas, and cloudkill. The cost in materials is 1,000 gold pieces per hit point, and it requires 3 months construction time. The golem created always remains under the control of the magic-user who created it. It can obey any simple commands. It will stand, non-functioning, as a guard until some event takes place, i.e. until a door is opened, a book read, etc. In addition to striking, an iron golem will breathe out a cloud of poisonous gas, 1" x 1" x 1", directly before it, once every 7 melee rounds. The strength of an iron golem is three times greater than that of a flesh golem. An iron golem can do 1 point of structural damage per melee round. An iron golem can be struck only by magical weapons of +3 or greater enchantment. Normal and magical weapons under +3 do no damage. The only magical attacks which affect the iron golem are electrical, such as a lightning bolt, which slows the monster 50% for 3 melee rounds. Magical fire attacks repair damage on a hit point for 1 hit point basis. Iron golems are subject to attack from rust monsters.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (60, 'Griffon', NULL, 'Uncommon', '2-12', '3', '12"/30"', '7', '25%', 'C, S', '3', '1-4/1-4/2-16', 'Nil', 'Nil', 'Standard', 'Semi-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Griffon.png', 'images/monsters/Griffon.png', 'Griffons seek cliffs and rocky habitats in which to build their nests. If conditions permit they will lair in a cave. They are aggressive carnivores, and their favorite prey are horses. If they come within sighting or smelling distance (36" as a general rule) of horseflesh, the griffons will wing to the hunt. They are much sought after in their fledgling state, for they can be tamed for use as fierce, loyal, steeds if obtained before maturity. If encountered in their lair, there is a 75% chance that there will be 1 or 2 eggs or young for every 2 griffons. The young are non-combative, but the adults will attack until killed. Fledglings sell for 5,000 gold pieces, eggs for 2,000, on the open market.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (61, 'Groaning Spirit (Banshee)', NULL, 'Very rare', '1', '0', '15"', '7', '70%', 'D', '1', '1-8', 'Its wail, or keening, will cause hearers within 3" to save versus magic or die on the spot; the sight of a groaning spirit causes fear unless an appropriate saving throw is made; it can wail but once per day, and only during darkness', '+1 or better weapon to hit; groaning spirits cannot be affected by charm, sleep, or hold spells; they are impervious to attack by cold or electricity', '50%', 'Exceptional', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Groaning_Spirit_(Banshee).png', 'images/monsters/Groaning_Spirit_(Banshee).png', 'The groaning spirit, or banshee, is the spirit of an evil female elf, a very rare thing indeed. The spirit returns to harm the living. It is found only in desolate countrysides, moors, etc. The groaning spirit can attack by its chilling touch, causing 1-8 hit points of damage per attack when it strikes. Its more fearsome mode of attack, however, is its wail, or keening, which will cause the hearers within 3" to save versus magic or die on the spot. The sight of a groaning spirit causes fear unless an appropriate saving throw is made. It can wail but once per day, and only during darkness. Groaning spirits cannot be affected by charm, sleep, or hold spells. They are impervious to attack by cold or electricity. Exorcism kills them.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (62, 'Halfling', NULL, 'Rare', '30-300', '7', '9"', '1-6 hit points', '70%', 'Individuals K, B in lair', '1', 'By weapon or 1-6', '+3 with bow or sling', 'Save at 4 levels higher', 'As above', 'Very', 'Lawful good', 'S (3''+ tall)', 'Nil*', 'Nil*', NULL, NULL, NULL, 'Halfling.png', 'images/monsters/Halfling.png', 'Halflings are basically hard-working, orderly and peaceful citizens of communities similar to humans — although their villages usually contain many burrow homes as well as surface cottages. For every 30 halflings encountered there will be two 2nd level fighters. If more than 90 are encountered there will be an additional leader of 3rd level fighting ability. If more than 150 are encountered there will also be the following additional halflings in the group: one 4th level fighter, two 3rd level fighters and three 2nd level fighters. If encountered in their lair there will be females and children equal to 100% and 60% respectively of the adult males indicated. A typical halfling lair will be in pastoral countryside. The usual protection worn by halflings consists of padded or leather armor. Halflings are typically weaponed as follows: small sword and short bow 10%, small sword and spear 10%, short bow 10%, sling 20%, small sword 10%, spear 20%, hand axe 20%. All halflings of above normal level will have armor class 6, while those of 3rd or 4th level will have armor class 5 and 4 respectively. All such higher levels will have a 10% chance per level of having magic armor and/or miscellaneous weapons. Halflings encountered in their lair will have from 1-4 dogs, treated as wild dogs for statistical purposes, per halfling. The magic and poison resistance of halflings causes them to save at four levels above their actual. They are exceedingly clever at both quiet movement and hiding. They will surprise on a die roll of 1-4 on a 6-sided die. In natural terrain they must be treated as invisible if they have any form of vegetation in which to conceal themselves. They have no infravision. They shun water. Halflings speak their own language, their alignment tongue, and the common speech. In addition they speak the language of gnomes, goblins, and orcs. Description: Of ruddy complexion, halflings tend toward brown or sandy brown hair coloration, and have brown or hazel eyes. Their dress is usually colorful, but their trousers and coats are likely to be serviceable grey, tan, or brown material. Halflings have a life expectancy of 150 or more years. Tallfellow: A taller (4+") slimmer halfling, with fairer skin and hair. Tallfellows are very rare. They use more armor (AC 6), ride ponies and carry more spears. It is possible for exceptionally strong (17, 18) tallfellows to work to 5th or 6th level of fighting ability. They can speak elvish and are very friendly with elves. They live for about 180 years on the average. Stout: This kind of halfling is a bit smaller (3½+") and stockier than the typical hairfeet. They use more armor also (AC 6), and employ morning stars in addition to the usual halflingish arms. Very strong stouts (18) are able to work up to 5th level fighting ability. Stouts have infravision and can detect sloping passageways. They have no fear of water and can swim. These halflings are able to speak dwarvish and enjoy dwarven company. Stouts reach the age of 200 or more years.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (63, 'Harpy', NULL, 'Rare', '2-12', '7', '6"/15"', '3', '25%', 'C', '3', '1-3/1-3/1-6', 'Singing and charm', 'Nil', 'Standard', 'Low', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Harpy.png', 'images/monsters/Harpy.png', 'Harpies have the bodies of vultures but the upper torsos and heads of women. They are voracious carnivores and foul creatures. Those that dwell along seacoasts are generally known as sirens. All harpies are able to emit sweet-sounding calls. Any creature hearing these calls will proceed towards the harpies unless they save versus magic. Similarly, the touch of a harpy charms those creatures which fail to make their saving throw versus magic. The harpies attack, torture, and devour their charmed prey. What they do not want they foul with excrement. A harpy attacks with her vulture claws and some form of weapon — often a bone club or some weapon left from one of her former victims. They speak their own language and none other.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (64, 'Lion', NULL, 'Uncommon', '2-12', '5/6', '12"', '5 + 2', '25%', 'Nil', '3', '1-4/1-4/1-10', 'Rear claws for 2-7/2-7 if a lion scores two paw hits during melee', 'Surprised only on a 1', 'Standard', 'Semi-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Lion.png', 'images/monsters/Lion.png', 'Lions generally inhabit warmer climates, warm temperate to tropical. They will thrive in any region, from desert to jungle, swamp to savannah. Lions hunt in packs, prides, the males seldom doing any actual stalking or killing of prey. The lioness is the real huntress. All these creatures can spring up to 30 feet. Males, however, are ferocious fighters, and will actively defend their group territory. Male lions have armor class 5 forequarters and armor class 6 hindquarters, while lionesses have armor class 6. A typical pride consists of 1-3 males and 1-9 females. If found in their lair there will be 1-10 cubs from 30% to 60% grown which will not fight. There will be 1-4 lionesses with these cubs which will immediately attack. Lions do not climb trees well and they dislike swimming. If a lion scores two paw hits during melee it gains the advantage of raking with its two rear claws that turn, each rake causing 2-7 points of damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (65, 'Mountain Lion', NULL, 'Uncommon', '1-2', '6', '15"', '3 + 1', '10%', 'Nil', '3', '1-3/1-3/1-6', 'Rear claws for 1-4/1-4', 'Surprised only on a 1', 'Standard', 'Semi-', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Mountain_Lion.png', 'images/monsters/Mountain_Lion.png', 'This creature is not actually a true lion, but a species of great cat. They inhabit forests and deserts as well as mountains. They are somewhat cautious, but they are fierce fighters if threatened or cornered. They can spring upwards 15 feet or ahead at least 20 feet to attack. Their rear claws each rake for 1-4 hit points damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (66, 'Spotted Lion', NULL, 'Rare', '2-8', '5/6', '12"', '6 + 2', '25%', 'Nil', '3', '1-4/1-4/1-12', 'Rear claws for 2-8/2-8 if a spotted lion scores two paw hits during melee', 'Surprised only on a 1', 'Standard', 'Semi-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Spotted_Lion.png', 'images/monsters/Spotted_Lion.png', 'Also known as cave lions, spotted lions are larger, spotted specimens of the common lion. They roam the plains of the pleistocene epoch, with but few being found elsewhere. Their hunting traits and group closely resemble those of their smaller, more modern kin. If a spotted lion scores two paw hits during melee it gains the advantage of raking with its two rear claws that turn, each rake causing 2-8 points of damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (67, 'Lizard Man', NULL, 'Rare', '10-40', '5 (4)', '6"/12"', '2 + 1', '30%', 'D', '3', '1-2/1-2/1-8', 'About 1 tribe in 10 has evolved to a higher state; these lizard men dwell in crude huts, use shields (thus armor class 4) and hurl barbed darts (3" range, 1-4 points damage) or javelins (1-6 hit points damage) before closing with enemies; in combat these advanced lizard men employ clubs (treat as morning stars)', 'Nil', 'Standard', 'Low (average)', 'Neutral', 'M (about 7'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Lizard_Man.png', 'images/monsters/Lizard_Man.png', 'Lizard men are semi-aquatic, breathing air but often (35%) dwelling totally underwater and having caves which are not water filled in which they lair. They are typically found in swamps, marshes, and similar places. They band together in rough tribal form. They are omnivorous, but lizard men are likely to prefer human flesh to other foods. In this regard they have been known to ambush humans, gather up the corpses and survivors as captives, and take the lot back to their lair for a rude and horrid feast. About 1 tribe in 10 has evolved to a higher state. These lizard men will dwell in crude huts, use shields (thus armor class 4) and hurl barbed darts (3" range, 1-4 points damage) or javelins (1-6 hit points damage) before closing with enemies. In combat these advanced lizard men employ clubs (treat as morning stars). They speak their own language.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (68, 'Bandit (Brigand)', NULL, 'Common', '20-200', 'See below', 'See below', '1-6 hit points', '20%', 'Individuals M, A in lair', '1', 'By weapon type', 'Leader types', 'Standard', 'Standard', 'Mean: average to very', 'Neutral (chaotic evil)', 'M', 'Leader types', 'Leader types', NULL, NULL, NULL, 'Bandit_(Brigand).png', 'images/monsters/Bandit_(Brigand).png', 'Bandits roam every clime from temperate to subtropical. They travel in groups, generally led by high level fighters, magic-users, and clerics. Those encountered in dungeons will be far fewer in number and often cooperating with thieves. For every 20 bandits encountered there will be an additional 3rd level fighter, for every 30 there will be an additional 4th level fighter, for every 40 there will be an additional 5th level fighter, and for every 50 there will be an additional 6th level fighter. Bandits will always be led by an 8th, 9th, or 10th level fighter, with 6 guards of 2nd level fighting ability and a lieutenant of 7th level. These 8 bandits are also in addition to the number indicated by the dice. To determine the level of the bandit leader use the following guide: if under 100 bandits are encountered the leader will be 8th level, if 100 to 150 the leader will be 9th level, and if 150 or more the leader will be 10th level. For every 50 bandits there is a 25% chance that there will be a magic-user of 7th, 8th, 9th, or 10th level, roll a 4-sided die for level if one is with the group, in addition, i.e. if there are 200 bandits there will always be a magic-user. For every 50 bandits there is a 15% chance that there will be a cleric of 5th or 6th level, with an assistant of 3rd or 4th level, dice only for the former, in addition. Bandit lairs will be informal camps 80% of the time, but 10% will be cave complexes with a secret entrance, and 10% will be regular castles with 1-4 light catapults for defense. Bandits will have from 2-20 important prisoners in their lair, as well as 5-30 camp followers/slaves. The mounting, armor, and arms of a force of bandits are: medium horse, chainmail and shield, sword 10%; light horse, leather armor and shield, spear 10%; light horse, leather armor, light crossbow 10%; leather armor and shield, sword 40%; leather armor, pole arm 10%; leather armor, light crossbow 10%; leather armor, short bow 10%. Terrain will vary the percentage of mounted bandits. In hilly and mountainous terrain no more than 10% of the total would be horsed, while in open country 90% of the force would be horsed. They have normal chances for having psionically endowed leader-types with a party. Brigands are chaotic evil bandits. They conform to the characteristics of bandits in general. The brigands will have a cave complex lair 20% of the time and a castle 30% of the time. They will have only 1-10 important prisoners, but there will be 20-50 camp followers/slaves. They have high morale in combat, so they get a +1 on reaction morale dice.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (69, 'Berserker', NULL, 'Rare', '10-100', '7', '12"', '2-7 hit points', '10%', 'Individuals K, B in lair', '1 (or 2)', 'By weapon type', 'Leader types', 'Leader types', 'Standard', 'Mean: average to very', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Berserker.png', 'images/monsters/Berserker.png', 'Berserkers are bands of fighters who gather together to go out and seek battle. They scorn armor and engage in combat mad with battle lust. This lust enables them to strike twice, or once with a +2 to hit. For every 10 berserkers encountered there will be a 1st level fighter in addition, for every 20 there will be a 2nd level, for every 30 there will be a 3rd, for every 40 there will be a 4th, and for every 50 there will be a 5th, all in addition to the number indicated by the dice. Berserkers will be led by a war chief of 9th or 10th level and two subchieftains of 6th or 7th level, if 60 or less berserkers, the lower levels, if more than 60, the higher levels. For every 10 berserkers encountered there is a 50% chance that there will be a berserk cleric of 7th level and 1-4 of his assistants of 3rd or 4th level. Berserkers never check morale. If they decide that a fight would bring them honor, and possibly loot, they will attack.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (70, 'Mind Flayer', NULL, 'Rare', '1-4', '5', '12"', '8 + 4', '50%', 'B, S, T, X', '4', '2 each', 'Mind blast', 'Nil', '90%', 'Genius', 'Lawful evil', 'M', '241-340', 'B/FGH', NULL, NULL, NULL, 'Mind_Flayer.png', 'images/monsters/Mind_Flayer.png', 'Mind flayers are found only in subterranean places, as they detest sunlight. They are greatly evil and consider the bulk of humanity, and its kin, as cattle to feed upon. The mind flayer''s physical attack is by striking a victim with its four tentacles. If a tentacle hits it will reach the opponent''s brain in 1-4 melee rounds and draw it forth, immediately killing the creature. The mind flayer then devours the brain. Its more feared attack mode, however, is the mind blast of psionic power. All within a 6 inch directional cone of ½ inch diameter at the point of emanation and 2 inches diameter at extreme range are affected, psionic attack on non-psionic. Mind flayers have the following psionic abilities: levitation, domination, ESP, body equilibrium, astral projection, probability travel. They perform at 7th level mastery. If an encounter is going against a mind flayer it will immediately flee, seeking to save itself regardless of its fellows or its treasure. These monsters speak only their own arcane language and several other weird tongues, purportedly those of terrible races of things which dwell in regions of the subterranean world far deeper than mankind has ever ventured. It is also rumored that these monsters have a city somewhere deep beneath the earth. The mind flayer''s skin glistens with slime. Its skin color is a nauseous mauve, its tentacles being purplish black. A mind flayer''s eyes are dead white, no pupil being evident. The three long fingers of each hand are reddish, but the hands are mauve.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (71, 'Minotaur', NULL, 'Rare', '1-8', '6', '12"', '6 + 3', '20%', 'C', '2', '2-8 or 1-4/By weapon type', 'Nil', 'Surprised only on a 1', 'Standard', 'Low', 'Chaotic evil', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Minotaur.png', 'images/monsters/Minotaur.png', 'Minotaurs are typically found only in labyrinthine places in the wilderness or underground. They are cruel, man-eaters, and although not particularly intelligent, they are cunning and have excellent senses. They are able to track prey by scent with 50% accuracy, and they will always pursue if it is in sight. They attack anything without fear, unless it is obviously beyond their ability to defeat. In combat the minotaur can butt an opponent of 6 feet or more in height, or bite a shorter one, the former attack doing 2-8, the latter 1-4, points of damage. The creature also uses some form of weapon, usually a huge axe, treat as a halberd, or a flail, +2 on damage. Minotaurs have their own language and are 25% likely to speak common as well.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (72, 'Mummy', NULL, 'Rare', '2-8', '3', '6"', '6 + 3', '80%', 'D', '1', '1-12', 'Fear', 'See below', 'See below', 'Low', 'Lawful evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Mummy.png', 'images/monsters/Mummy.png', 'Mummies are undead humans with existence on both the normal and the positive material planes. They are found near their tomb or in like burial places or ruins. They retain a semblance of life due to their evil, and they seek to destroy any living thing they encounter. Their unholy hatred of life and their weird un-life state gives them tremendous power, so that a blow from their arm smashes opponents for 1-12 hit points of damage. The scabrous touch of a mummy inflicts a rotting disease on any hit. The disease will be fatal in 1-6 months, and each month it progresses the diseased creature loses 2 points of charisma, permanently. It can be cured only by a magic spell, cure disease. The disease negates all cure wound spells. Infected creatures heal wounds at 10% of the normal rate. The mere sight of a mummy within 6 inches will cause such fear and revulsion in any creature that unless a saving throw versus magic is successful, the victim will be paralyzed with fright for 1-4 melee rounds. Note that numbers will give courage, and for each creature above 6 to 1 mummy, the creatures add +1 to their saving throw. If humans confront a mummy, each will save at +2 on his die. Mummies can be harmed only by magical weapons, and even those do only one-half normal damage, dropping all fractions, 5 becomes 2, 3 becomes 1, and 1 becomes 0 hit points of damage. Sleep, charm, hold, and cold-based spells have no effect upon them. Poison or paralysis do not harm them. A raise dead spell will turn the creature into a normal human, of 7th level fighting ability, naturally, unless the mummy saves versus magic. Mummies will suffer certain damage from fire, even flame of normal sort. A blow with a torch will cause 1-3 hit points of damage. A flask of burning oil will cause 1-8 hit points of damage on the first round it covers the mummy and twice that amount on the second melee round. Magical fires are at +1 per die of damage. If holy water is splashed upon them they suffer 2-8 hit points of damage for every vial-full which strikes. Any creature killed by a mummy rots and cannot be raised from death unless a cure disease and raise dead spell are used within 6 turns.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (73, 'Guardian Naga', NULL, 'Very rare', '1-2', '3', '15"', '11-12', '75%', 'H', '2', '1-6/2-8', 'Can spit poison at an individual creature at up to 3" range; if the victim fails its saving throw versus poison the spittle will kill; able to use clerical spells as if a 6th level cleric, i.e. 2 1st, 2 2nd, 1 3rd, and 1 4th level clerical spells per day', 'Nil', 'Standard', 'Exceptional', 'Lawful good', 'L (20'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Guardian_Naga.png', 'images/monsters/Guardian_Naga.png', 'Naga are snake-like creatures with good brains and magical abilities. They are encountered in warm climes in most cases. Wise and good, guardian naga are found principally in sacred places, guarding treasure of lawful good minions, or as watchers over some evil. In addition to poisonous biting for 1-6 points of damage, and constricting for 2-8 points, a guardian naga can spit poison at an individual creature at up to 3 inches range, and if the victim fails to make its saving throw versus poison the spittle will kill. Guardian naga also have the ability to use clerical spells as if they were 6th level clerics, i.e. 2 1st, 2 2nd, 1 3rd, and 1 4th level clerical spells per day. Guardian naga are covered in green-gold scales with silvery triangles along the back. Their eyes are golden.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (74, 'Spirit Naga', NULL, 'Rare', '1-3', '4', '12"', '9-10', '60%', 'B, T, X', '1', '1-3', 'Can permanently charm, as a charm spell, any humanoid creature that meets its gaze unless a saving throw versus paralyzation is made; able to use magical and clerical spells at 5th ability level of magic use and 4th level clerical ability, i.e. 4 1st, 2 2nd, and 1 3rd level magic-user spells and 2 1st and 1 2nd level cleric spells per day', 'Nil', 'Standard', 'High', 'Chaotic evil', 'L (15'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Spirit_Naga.png', 'images/monsters/Spirit_Naga.png', 'Naga are snake-like creatures with good brains and magical abilities. They are encountered in warm climes in most cases. Totally evil, spirit naga seek to do harm whenever and wherever possible. They prefer dwelling in ruined, dismal, or subterranean places. In addition to a poisonous bite for 1-3 hit points damage, these monsters can permanently charm, as a charm spell, any humanoid creature that meets a gaze of these monsters unless a saving throw versus paralyzation is made. Finally, spirit naga are able to use magical and clerical spells at 5th ability level of magic use and 4th level clerical ability, i.e. 4 1st, 2 2nd, and 1 3rd level magic-user spells and 2 1st and 1 2nd level cleric spells per day. Spirit naga are black scaled with crimson bands. Their heads are bulbous and have a very human appearance, even to coloration and hair.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (75, 'Water Naga', NULL, 'Uncommon', '1-4', '5', '9"/18"', '7-8', '45%', 'D', '1', '1-4', 'Able to employ magic spells, excluding those which deal with fire, of 5th level ability, i.e. 4 1st, 2 2nd, and 2 3rd level magic-user spells per day', 'Nil', 'Standard', 'Very', 'Neutral', 'M (10'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Water_Naga.png', 'images/monsters/Water_Naga.png', 'Naga are snake-like creatures with good brains and magical abilities. They are encountered in warm climes in most cases. Found only in clear, fresh water, these creatures are curious but quite neutral in attitude. They seldom attack unless threatened or attacked first. As they generally inhabit places many feet beneath the surface of a pool, lake, or river, they are seldom disturbed in their lair. In addition to their poisonous bite for 1-4 points of damage, water naga are able to employ magic spells, excluding those which deal with fire, of 5th level ability, i.e. 4 1st, 2 2nd, and 2 3rd level magic-user spells per day. Water naga are emerald green to turquoise in reticulated pattern with chocolate brown and pale jade green or dark gray and olive. Their eyes are pale green to bright amber.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (76, 'Nightmare', NULL, 'Very rare', '1', '-4', '15"/36"', '6 + 6', 'Nil', 'Nil', '3', '2-8/4-10/4-10', 'Nil', 'Breathes out a smoking, hot cloud during combat which obscures vision by blinding the eyes and choking its opponent; unless a saving throw is made the opponent attacks at -2 to hit and damage dice; can fly, become ethereal, and roam the astral plane', 'Standard', 'High', 'Neutral (evil)', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Nightmare.png', 'images/monsters/Nightmare.png', 'Also known as demon horses and hell horses, nightmares are creatures from the lower planes. They are ridden primarily by the more powerful demons and devils as well as by night hags. On occasion they serve as steeds for undead such as spectres, vampires and liches. The nightmare attacks with its great fangs as well as its burning hooves. These creatures breathe out a smoking, hot cloud during combat, and it obscures vision by blinding the eyes and choking its opponent. Unless a saving throw is made the opponent attacks at -2 to hit and damage dice. Nightmares can fly, become ethereal, and roam the astral plane. They hate material life and attack viciously, even without a rider to command them. The hell horse is gaunt and skeletal with a huge head, glowing red eyes, flaming orange nostrils, and hooves which burn like embers. The coat is dead black, and the creature''s mane and tail are wild and rugged.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (77, 'Ogre', NULL, 'Common', '2-20', '5', '9"', '4 + 1', '20%', 'Individuals M (x10), Q, B, S in lair', '1', '1-10 or by weapon', 'Nil', 'Nil', 'Standard', 'Low', 'Chaotic evil', 'L (9''+ tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Ogre.png', 'images/monsters/Ogre.png', 'Ogres can be found in virtually any terrain, including subterranean places. They are ugly-tempered and voracious. Ogres are also fond of treasure, and they will sometimes be found serving as mercenaries in the ranks of orc tribes or evil clerics or joining with gnolls for a profitable raid. Ogres mingle freely with trolls and some giants, and they are at times enslaved by certain demons. If 11 or more ogres are encountered, there will be one who is a leader, armor class 3, 30-33 hit points, attacking as a 7 hit dice creature and doing 2-12 hit points damage per attack. If 16 or more are encountered there will be 2 such leaders plus 1 additional ogre, a chieftain with armor class 4, 34-37 hit points, and attacking as a 7 hit dice monster and doing 4-14 hit points damage per attack. If weapon type is used to determine damage per attack, give a standard bonus of +2 hit points to ogres and leaders/chieftains gain an additional +1/+2 bonus. If ogres are found in their lair there will be 2-12 females who fight as normal ogres but do only 2-8 points of damage and take a maximum of 6 hit points per hit die. There will also be 2-8 young who will fight as goblins. Ogres will take prisoners in order to use them as slaves, 25%, or food, 75%, so there is a 30% chance that an ogre lair will contain 2-8 slaves/prisoners. As they are very fond of halfling, dwarf, or elf flesh, there is only a 10% chance that such creatures will be found alive in an ogre lair. Ogres speak their own language as well as that of chaotic evil, orcs, trolls, and stone giants. The hide of ogres varies from dull blackish-brown to dead yellow. Rare specimens are a sickly violet in color. Their warty bumps are often of different color, or at least darker than their hides. Hair is blackish-blue to dull dark green. Eyes are purple with white pupils. Teeth are black or orange, as are talons. Ogres wear any sort of skins or furs. They care for their arms and armor reasonably well. The life span of an ogre is not less than 90 years.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (78, 'Orc', NULL, 'Common', '30-300', '6', '9"', '1', '35%', 'Individuals L; C, O, Q (x10), S in lair', '1', '1-8 or by weapon type', 'Nil', 'Nil', 'Standard', 'Average (low)', 'Lawful evil', 'M (6''+ tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Orc.png', 'images/monsters/Orc.png', 'Orc tribes are fiercely competitive, and when they meet it is 75% likely that they will fight each other unless a strong leader, such as a wizard, evil priest, or evil lord, with sufficient force behind him is on hand to control the orcs. Being bullies, the stronger will always intimidate and dominate the weaker. If goblins are near, for example, and the orcs are strong enough, they will happily bully them. Orcs dwell in places where sunlight is dim or non-existent, for they hate the light. In full daylight they must deduct 1 from their dice rolls to hit opponents, but they see well even in total darkness, infravision. Known orc tribes include the following: Vile Rune, Bloody Head, Death Moon, Broken Bone, Evil Eye, Leprous Hand, Rotting Eye, Dripping Blade. If orcs from one of those tribes are encountered in an area, it is likely that all other orcs nearby will also be from this tribe. For every 30 orcs encountered there will be a leader and 3 assistants. These orcs will have 8 hit points each, being the biggest, strongest, meanest in their group. If 150 or more orcs are encountered there will be the following additional figures with the band: a subchief and 3-18 guards, each having armor class 4, 11 hit points, and fighting as monsters with 2 hit dice, doing 2-7 hit points damage. If the orcs are not in their lair there is a 20% chance they will be escorting a train of 1-6 carts and 10-60 slave bearers bringing supplies and loot to their chief or to a stronger orc tribe. The carts will hold goods worth from 10 to 1,000 gold pieces, and each slave bearer will bear goods worth from 5 to 30 gold pieces. If such a train is indicated, double the number of leaders and assistants, add 10 normal orcs for each cart in the train, and a subchief with 5-30 guards will always be in charge. Orc lairs are underground 75% of the time, in an above ground village 25% of the time. There will always be the following additional orcs when the encounter is in the creature''s lair: a chief and 5-30 bodyguards, armor class 4, 13-16 hit points, attack as monsters with 3 hit dice and do 2-8 hit points damage, females equal to 50% of the number of males, young equal to 100% of the number of males. If the lair is underground, there is a 50% chance that there will be 2-5 ogres living with the orcs. If the lair is above ground it will be a rude village of wooden huts protected by a ditch, rampart, and log palisade. The village will have from 1-4 watch towers and single gate. There will be 1 catapult and 1 ballista for each 100 male orcs, round to the nearest hundred. The weaponry of orcs is shown typically below: sword and flail 5%, sword and spear 10%, axe and spear 10%, axe and pole arm 10%, axe and crossbow 10%, axe and bow 10%, sword and battleaxe 5%, spear 10%, axe 10%, polearm 20%. Leaders and above will always have two weapons. If a subchief is with a group the tribal standard will be present 40% of the time. The standard is always present when the tribal chief is. The standard will cause all orcs within 6 inches to fight more fiercely, +1 on hit dice and morale check dice. Orcs are cruel and hate living things in general, but they particularly hate elves and will always attack them in preference to other creatures. They take slaves for work, food, and entertainment, torture, etc., but not elves whom they kill immediately. Orcs are accomplished tunnelers and miners. They note new or unusual constructions underground 35% of the time and spot sloping passages 25% of the time. The majority of orcs speak goblin, hobgoblin, and ogre in addition to the languages of orcs and lawful evil. Orcs appear particularly disgusting because their coloration, brown or brownish green with a bluish sheen, highlights their pinkish snouts and ears. Their bristly hair is dark brown or black, sometimes with tan patches. Even their armor tends to be unattractive, dirty and often a bit rusty. Orcs favor unpleasant colors in general. Their garments are in tribal colors, as are shield devices or trim. Typical colors are blood red, rust red, mustard yellow, yellow green, moss green, greenish purple, and blackish brown. They live for 40 years. Half-Orcs: As orcs will breed with anything, there are any number of unsavory mongrels with orcish blood, particularly orc-goblins, orc-hobgoblins, and orc-humans. Orcs cannot cross-breed with elves. Half-orcs tend to favor the orcish strain heavily, so such sorts are basically orcs although they can sometimes, 10%, pass themselves off as true creatures of their other stock, goblins, hobgoblins, humans, etc.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (79, 'Owl, Giant', NULL, 'Rare', '2-5', '6', '3"/18"', '4', '5%', 'Q (x5), X', '3', '2-8/2-8/2-5', 'Surprise on a 1-5', 'Nil', 'Standard', 'Very', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Owl,_Giant.png', 'images/monsters/Owl,_Giant.png', 'Giant owls are rarely encountered as they inhabit only very wild areas. They are nocturnal predators and effective hunters. Giant owls speak their own language. A giant owl strikes with its two sets of sharp talons and its strong beak. Its feathers allow it to fly with nearly absolute silence, thus it surprises on 1-5 on a 6-sided die. These creatures are intelligent and will sometimes befriend other creatures. If encountered in their lair there is a 20% chance that there will be 1-3 eggs, 25%, or 1-3 hatchling owls, 20% to 70% grown. The parents will always attack any creature threatening the eggs or owlets. Eggs sell for 1,000 gold pieces, young for 2,000, on the open market.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (80, 'Pegasus', NULL, 'Very rare', '1-10', '6', '24"/48"', '4', '15%', 'Nil', '3', '1-8/1-8/1-3', 'Nil', 'Nil', 'Standard', 'Average', 'Chaotic good', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Pegasus.png', 'images/monsters/Pegasus.png', 'Pegasi are found in remote places, for they are typically very shy and wild. These intelligent winged horses make the swiftest of steeds, and they are often sought for that reason. Pegasi will serve only good characters, but if they do so, they always serve unto death. A pegasus fights with its two forehooves and its powerful teeth. A male specimen can carry weight equal to a medium warhorse, a female equal to a light warhorse. If encountered in their lair there will be 1 nest for every pair of pegasi. There is a 20% chance per nest that there will be 1-2 eggs, 30%, or young animals, 70%, of 20% to 50% maturity. The eggs are worth 3,000 gold pieces, the young 5,000, on the open market.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (81, 'Pixie', NULL, 'Very rare', '5-20', '5', '6"/12"', '1-4 hit points', '5%', 'R, S, T, X', '1', 'By weapon type', 'See below', 'See below', '25%', 'Exceptional', 'Neutral', 'S (2½'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Pixie.png', 'images/monsters/Pixie.png', 'Pixies dwell only in the most idyllic of woodlands. They are naturally invisible and are thus almost never noted even though some creature passes near their secluded home. Pixies normally carry slim swords and fine bows similar to those of sprites. Their swords are equal to daggers, but their arrows are more effective and are of three types. All have +4 chance to hit. The pixie war arrow inflicts 2-5 hit points of damage. Their second type causes sleep in a comatose state for 1-6 hours to any creature which fails to save versus magic when struck. The third sort which the pixies use causes no harm physically, but being struck causes a complete loss of memory which can only be restored by clerical exorcism unless the victim saves versus magic. Pixies can become visible at will, polymorph themselves at will, create illusions with both audial and visual components which last without concentration until magically dispelled once per day each, and know alignment. Pixies can, by touch, cause confusion in any creature which fails its saving throw versus magic. Confusion is permanent unless a remove curse spell is applied. Once per day pixies are able to use dispel magic at 8th level ability, dancing lights, ESP, and 1 in 10 can use Otto''s Irresistible Dance spells. Because pixies are normally invisible, they gain the advantage of subtracting 4 from to hit dice rolls of all opponents unable to detect invisible objects. Similarly, pixies can attack while invisible. Pixies are highly mischievous, and they will be prone to bother, harass, or fool creatures. They speak their own tongue, that of sprites, and common speech.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (82, 'Pseudo-Dragon', NULL, 'Very rare', '1', '2', '6"/24"', '2', '5%', 'Q (x10)', '1', '1-3', 'Poison sting', 'Chameleon power', '35%', 'Average', 'Neutral (good)', 'S (1½'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Pseudo-Dragon.png', 'images/monsters/Pseudo-Dragon.png', 'Pseudo-dragons are found in any clime, save the coldest or hottest, when they are found at all. These creatures are rare indeed and highly sought after. They lair in great hollow trees or small caves. The pseudo dragon can deliver a vicious bite with its small, dragon-like jaws, but its major weapon is its sting-equipped tail. This appendage is long and very flexible. The creature can move it with flashing speed, and strikes at +4 to its to hit dice. Any creature struck must save versus poison or go into a state of catalepsy which lasts for 1-6 days. During this time the victim appears dead and there is a 25% chance the creature will actually die. Pseudo-dragons have a chameleon-like power, so that they can blend with any typical background and become 80% undetectable to creatures not able to see invisible objects. They can see invisible objects. Magic resistance is an innate characteristic of pseudo-dragons, and they are able to transmit this resistance to a human, or humanoid, companion when the pseudo-dragon is touching the other creature. A pseudo-dragon communicates by means of a limited form of telepathy. If the pseudo-dragon elects to become a companion of a human, or humanoid, it can also transmit what it sees and hears to its companion up to a distance of 24 inches. Pseudo-dragons appear exactly as miniature red dragons. However, their coloration is a basic red brown, and can be changed as noted.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (83, 'Purple Worm', NULL, 'Rare', '1-2', '6', '9"', '15', '30%', 'B, Q (x5), X', '1 and 1', '2-24/2-8', 'See below', 'Nil', 'Standard', 'Non-', 'Neutral', 'L (50'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Purple_Worm.png', 'images/monsters/Purple_Worm.png', 'Purple worms burrow deep beneath the ground in a constant search for food. They sense vibrations at 60 feet and move to attack. Generally only adult specimens, 8-9 feet in diameter and 40-50 feet long, are encountered. Young are 1 foot in diameter and about 5 feet when they hatch, a typical hatching being 10-20, each with 1 hit die + 4 hit points. They return to their lairs to rest, and there they expel such indigestible waste as metal and mineral crystals. A purple worm attacks by biting, 2-24 points of damage, and any hit 20% over the required score, that is 4 or more over the required number, or a 100%, die roll of 20, score in any case indicates the creature has engulfed its victim. A mature purple worm can swallow whole a creature as large as 8 feet or so tall and up to 6 feet wide, or vice versa. Any creature swallowed will be dead in 6 melee rounds. The worm will digest its meal in 12 turns, and at that time the creature is totally gone and cannot be raised from the dead. Note, however, that a creature swallowed can try to cut its way out of the purple worm''s stomach. The inner armor class of the worm is 9, but each round the creature is in the worm it subtracts 1 from the damage each of its attacks does. This subtraction is cumulative, so on the second melee round there is a -2, on the third a -3, etc. Additionally, the purple worm has a poisonous stinger in its tail. This weapon is only used in rear defense, however, or if the worm is fighting large or numerous opponents in a very spacious area which will allow it freedom to use its stinger. The sting causes 2-8 hit points of damage when it hits, and if the victim fails its poison saving throw it is killed by the purple worm''s poison. Mottled Worm: The mottled worm is an aquatic variety of the purple worm. It inhabits shallow bottom muck but will surface for prey. It otherwise conforms to the characteristics of the purple variety.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (84, 'Quasit', NULL, 'Very rare', '1', '2', '15"', '3', '0%', 'Q (x3)', '3', '1-2/1-2/1-4', 'See attacks', 'See below', '25%', 'Low', 'Chaotic evil', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Quasit.png', 'images/monsters/Quasit.png', 'While the quasit is rare on the material plane, they are not on the planes of Pandemonium and the Abyss. The quasit is a larva changed into a minor demon form to serve as familiar to a chaotic evil magic-user or cleric. A quasit is able to polymorph itself into the shape of any two of the following creatures, this power being given to it by its demon lord: giant centipede, bat, frog, or wolf. The attack mode of an unpolymorphed quasit is by means of its claws and fangs. The wounds caused by its claws cause a burning itch which drains 1 from its opponent''s dexterity each time it is wounded unless a saving throw versus poison is made. Dexterity loss remains for 2-12 melee rounds. The magical powers of a quasit are held by its polymorphed form also. All quasits detect both good and magic. They regenerate at 1 hit point per melee round. They can become invisible at will, and once per day they can send out a blast of fear in a 3 inch radius. Only magical or cold iron weapons will harm these monsters. Cold, fire, and lightning do not affect them. For purposes of spell attack upon them, quasits are considered as 7 hit dice creatures. Although intelligence is low, quasits are sly and cunning, and in certain situations they are able to call upon the thinking power of a demon lord. Once the quasit becomes a familiar, it passes along to its master telepathic communication which enables the character to use all senses, including infravision, of the familiar, even up to a mile away. The quasit’s presence within 1 inch of its master allows the latter the quasit’s magic resistance, 25%, and also enables regeneration at 1 hit point per melee round. When the quasit is within a mile of its master, the latter gains an additional level of ability. If the quasit is farther away, the character loses 1 level, and if the quasit is killed, the loss to the character is 4 levels. Finally, in addition to its normal advice, the quasit is able to contact a lower plane once per week in order to help its master decide some course of action. This contact is like a commune spell, but 6 questions are allowed. The major aim of a quasit is to enable its master to wreak greater and more chaotic evil. It also wishes to destroy lawful evil humans in order to steal their souls for the demons, as the quasit will be rewarded accordingly when and if it returns to the planes of the Abyss. At the time of its master''s death the quasit must grab the soul and rush back to there, and if it has not been actively evil prior to that, its demon lord might change the quasit to a manes or larva or send it forth as a quasit again rather than making it into a type I or II demon.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (85, 'Roc', NULL, 'Rare', '1-2', '4', '3"/30"', '18', '10%', 'C', '2 or 1', '3-18/3-18 or 4-24', 'Nil', 'Nil', 'Standard', 'Animal', 'Neutral', 'L (60''+ wingspread)', 'Nil', 'Nil', NULL, NULL, NULL, 'Roc.png', 'images/monsters/Roc.png', 'Rocs are huge birds somewhat resembling eagles. They inhabit the highest mountains in warm regions. They prey upon large creatures such as cattle, horses, and elephants. The roc swoops down upon prey, seizes it in its powerful talons, and carries it off to its lair. If the creature resists, the roc will strike it with its beak, inflicting 4-24 points of damage per hit. The lair of a roc will be a vast nest of trees, branches, and the like. There its treasure will be strewn about, for the creature does not value such; it is the residue of its victims. Rocs are occasionally tamed and used by giants.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (86, 'Salamander', NULL, 'Rare', '2-5', '5/3', '9"', '7 + 7', '75%', 'F', '2', 'By weapon type/2-12', 'Heat', '+1 or better weapon to hit', 'Standard', 'High', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Salamander.png', 'images/monsters/Salamander.png', 'Salamanders are creatures of the elemental plane of fire. They come to the material plane occasionally for purposes known only to them. Salamanders hate cold, preferring temperatures of 300 degrees upwards, and they can abide lower temperatures only for a few hours. Their lair is typically at least 500 degrees temperature, and such treasure as is found there will be the sort to survive such heat. The human-like upper body of a salamander has an armor class of 5, while the lower body is armor class 3. A salamander typically attacks with a metal spear which inflicts damage of 1-6 hit points plus a like amount for its heat. At the same time it can lash out and coil around an opponent with its snake-like tail, constricting for 2-12 hit points damage plus causing an additional 1-6 points of damage from the heat of its body. While fire resistant creatures will not suffer heat damage, they will be subject to normal attack damage. Salamanders can be affected only by magical weaponry or by creatures of a magical nature or with great strength. They are impervious to all fire-based attacks. Sleep, charm, and hold spells are ineffective against them. Cold based attacks cause an additional 1 point of damage per die of attack value. The head and torso of a salamander is copper-colored, with yellow, glowing eyes. The lower body is an orange shading to dull red at the tail end.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (87, 'Satyr', NULL, 'Uncommon', '2-8', '5', '18"', '5', '40%', 'I, S, X', '1', '2-8', 'See below', 'See below', '50%', 'Very', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Satyr.png', 'images/monsters/Satyr.png', 'Satyrs, or fauns, inhabit only sylvan woodlands. They are interested primarily only in sport, frolicking, piping, chasing wood nymphs, etc. They resent intrusion, however, and will drive away any creature which offends them. They can sometimes be lured or bribed with superior wine. A satyr normally attacks by butting with its two sharp horns. They will occasionally, 20%, make use of magical weapons. It is quite likely that a satyr will first play a tune on his pipes, an instrument only a satyr can properly employ. By means of these pipes the satyr can charm, sleep, or cause fear in all within a 6 inch hearing radius unless they save versus magic. Only 1 satyr per band is likely to have pipes. If comely females are in the group the piping will be to charm, if the intruder is relatively inoffensive the piping will be to sleep, and choice items will be stolen from the sleeper, but if the party is powerful the piping will be to cause fear. Any creature which saves versus any form of piping is not affected by additional music from the same pipes. Satyrs are very silent and have keen senses. They are surprised only on a 1, and they can blend with foliage so as to be 90% undetectable to creatures not able to see hidden or invisible things. These creatures have their own tongue and are also able to speak elvish, understandable only to sylvan elves, and the common speech. Satyrs dwelling near centaurs are 80% likely to be friendly with the latter, cooperating with them and speaking their language. The skin of the upper body of a satyr is tan to light brown, its hair elsewhere being medium brown, reddish brown, or dark brown. Horns and hooves are black.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (88, 'Shadow', NULL, 'Rare', '2-20', '7', '12"', '3 + 3', '40%', 'F', '1', '2-5', 'Strength drain', '+1 or better weapon to hit', 'See below', 'Low', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Shadow.png', 'images/monsters/Shadow.png', 'These horrible undead creatures are found amidst ancient ruins or deep beneath the ground. As they exist primarily on the negative material plane they drain strength by merely touching an opponent. They attack living things without hesitation in order to gain the life force of their prey. In addition to the 2-5 hit points of damage their chill touch causes, each hit also saps 1 point of the victim''s strength. If a human opponent reaches 0 strength or hit points, the shadow drains his life force and he becomes a shadow. Note that strength returns to a creature 2-8 turns after being touched. Shadows are not affected by sleep, charm or hold spells. They are not subject to cold-based attacks. Shadows are 90% undetectable, as they appear to be nothing more than their name. If bright light is cast, such as from a continual light spell, they can be clearly seen.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (89, 'Shedu', NULL, 'Rare', '2-8', '4', '12"/24"', '9 + 9', '25%', 'G', '2', '1-6/1-6', 'See below', 'See below', '25%', 'Exceptional', 'Lawful good', 'L', '70-100', 'All/all', NULL, NULL, NULL, 'Shedu.png', 'images/monsters/Shedu.png', 'Shedu travel about the world seeking to further the ends of lawful good, helping allied creatures when in need. Although shedu can attack with their powerful front hooves, they are more likely to use their psionic abilities, 3 major and 5 minor disciplines. All such abilities are performed at 9th level of mastery. Shedu can become ethereal at will, and they frequently travel the astral and ethereal planes. Shedu have their own language and know most human tongues; as they have a limited form of telepathy, shedu generally communicate by direct mind contact.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (90, 'Shrieker', NULL, 'Common', '2-8', '7', '1"', '3', '0%', 'Nil', '0', 'Nil', 'Nil', 'Noise', 'Standard', 'Non-', 'Neutral', 'S to L', 'Nil', 'Nil', NULL, NULL, NULL, 'Shrieker.png', 'images/monsters/Shrieker.png', 'Shriekers are normally quiet, mindless fungus which are ambulatory. They live in dark places beneath the ground. Light within 30 feet or movement within 10 feet will cause them to emit a piercing shriek which lasts for 1-3 melee rounds. This noise has a 50% chance of attracting wandering monsters each round thereafter. Purple worms and shambling mounds greatly prize shrieker as food.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (91, 'Skeleton', NULL, 'Rare', '3-30', '7', '12"', '1', 'Nil', 'Nil', '1', '1-6', 'Nil', 'See below', 'See below', 'Non-', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Skeleton.png', 'images/monsters/Skeleton.png', 'Skeletons are magically animated, undead monsters. They are enchanted by a powerful magic-user or cleric of evil alignment. The skeletons perform according to the command of their animator, the command being limited in scope to but a dozen or two words. They are found only in burial places or dungeons and similar forsaken places. The skeleton strikes with some form of weapon, but regardless of the weapon type the damage caused by a hit will be 1-6 hit points. Skeletons suffer only one-half damage from sharp and/or edged weapons, such as spears, daggers, swords. Blunt weapons such as clubs, maces, flails, etc. score normal damage. Fire scores normal damage. Sleep, charm, hold and cold-based spells do not affect skeletons. Holy water causes 2-8 hit points of damage on a skeleton for each vial which strikes it. Skeletons attack until destroyed.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (92, 'Amphisbaena', NULL, 'Very rare', '1-3', '3', '12"', '6', '0%', 'Nil', '2', '1-3/1-3', 'Poison', 'See below', 'Standard', 'Animal', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Amphisbaena.png', 'images/monsters/Amphisbaena.png', 'Giant snakes are likely to be found in any clime save the coldest. All are carnivorous. These monsters have heads at both ends, and both heads are armed with poisonous fangs. The creature travels by grasping one of its necks and rolling like a hoop. It is able to attack with both heads, and victims failing to save versus poison when bitten die instantly. Cold-based attacks do not harm the amphisbaena.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (93, 'Snake, Giant Constrictor', NULL, 'Uncommon', '1-2', '5', '9"', '6 + 1', '0%', 'Nil', '2', '1-4/2-8', 'Constriction', 'Nil', 'Standard', 'Animal', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Snake,_Giant_Constrictor.png', 'images/monsters/Snake,_Giant_Constrictor.png', 'Giant snakes are likely to be found in any clime save the coldest. All are carnivorous. These snakes usually drop coils from above, grab prey within their coils, deliver a bite, and then constrict causing 2-8 points of damage per melee round. If several strong creatures, such as 4 humans of 16 or greater strength, can grasp the creature at head and tail ends, they can uncoil it in 2-5 melee rounds. After eating, the snake sleeps for a period of several days.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (94, 'Snake, Giant Poisonous', NULL, 'Uncommon', '1-6', '5', '15"', '4 + 2', '0%', 'Nil', '1', '1-3', 'Poison', 'Nil', 'Standard', 'Animal', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Snake,_Giant_Poisonous.png', 'images/monsters/Snake,_Giant_Poisonous.png', 'Giant snakes are likely to be found in any clime save the coldest. All are carnivorous. Giant poisonous snakes need no lengthy explanation or description. Some varieties, however, are worth noting, as their poison is so strong that even if a saving throw is made the victim takes up to 3-18 hit points damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (95, 'Snake, Giant Sea', NULL, 'Uncommon', '1-8', '5', '12"', '8-10', '0%', 'Nil', '2', '1-6/3-18', 'Constriction', 'Nil', 'Standard', 'Animal', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Snake,_Giant_Sea.png', 'images/monsters/Snake,_Giant_Sea.png', 'Giant snakes are likely to be found in any clime save the coldest. All are carnivorous. Found only in tropical waters, these marine creatures attack only when hungry, 20% chance. They otherwise ignore other creatures unless molested. Sea snakes have a poisonous bite. The largest are able to coil about small vessels and crush them at a rate of 10% of total value per melee round of constriction.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (96, 'Snake, Giant Spitting', NULL, 'Rare', '1-4', '5', '12"', '4 + 2', '0%', 'Nil', '1', '1-3', 'See below', 'Nil', 'Standard', 'Animal', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Snake,_Giant_Spitting.png', 'images/monsters/Snake,_Giant_Spitting.png', 'Giant snakes are likely to be found in any clime save the coldest. All are carnivorous. The spitting giant snake is a variety of the poisonous type which can emit a poisonous spittle, spraying it up to 3 inches at any single creature. The victim must save versus poison. Naturally, the bite of these snakes is likewise poisonous. Giant spitting cobras are a typical example of the monster.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (97, 'Spectre', NULL, 'Rare', '1-6', '2', '15"/30"', '7 + 3', '20%', 'Q (x3), X, Y', '1', '1-8', 'Energy drain', '+1 or better weapon to hit', 'See below', 'High', 'Lawful evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Spectre.png', 'images/monsters/Spectre.png', 'Spectres are very powerful undead humans whose primary existence is on the negative material plane. Spectres haunt the most desolate of places, tombs, and dungeons. They hate sunlight and living things. Daylight makes them powerless. Life makes them lament their unlife. A spectre''s chilling touch causes 1-8 hit points of damage and drains 2 life energy levels from an opponent, the latter due to the negative force of the spectre. Thus, an 11th level character, or an 11 hit dice creature, struck by a spectre would suffer 1-8 hit points of damage plus loss in level ability, hit dice, etc. Such loss is permanent, but characters can regain lost levels through continued acquisition of experience points, of course. Certain magic might restore lost levels as well. Spectres are not affected by sleep, charm, hold, or cold-based spells. Poison or paralyzation do not harm spectres. Holy water causes a spectre to suffer 2-8 hit points of damage for every vial-full which hits it. A raise dead spell will destroy a spectre unless it makes its saving throw versus magic. Any human totally drained of life energy by a spectre becomes a half-strength spectre under the control of the spectre which drained him.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (98, 'Sprite', NULL, 'Rare', '10-100', '6', '9"/18"', '1', '20%', 'C', '1', 'By weapon type', 'See below', 'See below', 'Standard', 'Very', 'Neutral (good)', 'S (2'' tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Sprite.png', 'images/monsters/Sprite.png', 'Sprites dwell in meadows and wooded glens. They are very shy and reclusive, but they hate evil and ugliness of all sorts. They are armed with slim swords, equal to daggers, and small bows with but half the range and effect of a short bow. However, their arrows are coated with a special ointment which causes any creature struck to save versus poison or sleep for 1-6 hours in a comatose state. The sprites will then slay evil creatures or remove good ones to a place far from where they encountered the sprites. Note that sprites are 75% likely to be unnoticed by any creature, and they will attack only evil creatures unless molested first. Sprites are able to become invisible at will, detect good and evil at 5 inches range, and move silently. When invisible they cause opponents to strike with a -4 on to hit dice. Sprites speak their own language and the common tongue.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (99, 'Sylph', NULL, 'Very rare', '1', '9', '12"/36"', '3', '10%', 'Q (x10), X', '0', 'Nil', 'See below', 'See below', '50%', 'Exceptional', 'Neutral (good)', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Sylph.png', 'images/monsters/Sylph.png', 'Sylphs are very beautiful creatures similar to nymphs. The sylphs, however, dwell primarily in aerial places. They are fond of flitting about, and it is not likely that they will be encountered near the place where they dwell. Sylphs sometimes, 20%, befriend creatures of good alignment, aiding them in some way. A sylph has magical ability of 7th level, 4 1st level spells, 3 2nd, 2 3rd, and 1 4th once per day, in addition to the abilities of invisibility at will and conjuring an air elemental once per week. Sylphs speak their own and the common tongue.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (100, 'Tiger', NULL, 'Uncommon', '1-4', '6', '12"', '5 + 5', '5%', 'Nil', '3', '2-5/2-5/1-10', 'Rear claws for 2-8/2-8', 'Surprised only on a 1', 'Standard', 'Semi-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Tiger.png', 'images/monsters/Tiger.png', 'Tigers range from subarctic to tropical areas, for they are highly adaptable and superb hunters. They often hunt in pairs or family groups. They climb well, can leap 10 feet upwards and 30 to 50 feet ahead in attack. If encountered in their lair there is a 25% chance that there will be 1-3 cubs there, these young having no effective attacks, and are from 30% to 60% mature. When they score 2 forepaw hits in one melee round, tigers also get 2 additional rear claw attacks each at 2-8 hit points damage that round.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (101, 'Sabre-Tooth Tiger (Smilodon)', NULL, 'Rare', '1-2', '6', '12"', '7 + 2', '10%', 'Nil', '3', '2-5/2-5/2-12', 'Rear claws for 2-8/2-8', 'Surprised only on a 1', 'Standard', 'Animal', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Sabre-Tooth_Tiger_(Smilodon).png', 'images/monsters/Sabre-Tooth_Tiger_(Smilodon).png', 'The most aggressive and fearsome predator of the Pleistocene epoch, these giants are seldom encountered elsewhere. They range only in warm regions but otherwise conform to the characteristics of normal tigers. Their six inch long fangs inflict terrible wounds, and the size of these teeth, along with the power of the sabre-tooth tiger''s jaws, give the creature a +2 on to hit dice.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (102, 'Tick, Giant', NULL, 'Rare', '3-12', '3', '3"', '2-4', '0%', 'Nil', '1', '1-4', 'Blood drain', 'Nil', 'Standard', 'Non-', 'Neutral', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Tick,_Giant.png', 'images/monsters/Tick,_Giant.png', 'Giant ticks are found in forests and occasionally in caves or caverns as well. These insects seek to drop upon prey, insert their hollow mouthtube, and suck blood from the victim. A hit by a giant tick scores 1-4 points of damage and indicates the monster has attached itself. Each melee round thereafter it will drain 1-6 hit points of blood, until reaching satiation at a blood drain equal to its hit points, when it drops off. A giant tick must be killed, severely burned, or immersed in water to detach it prior to satiation. Any creature bitten has a 50% chance of contacting a fatal disease from the tick. The disease will be fatal in 2-8 days unless a cure disease spell is cast upon the victim.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (103, 'Titan', NULL, 'Very rare', '1-2 (10%)', '2 to -3', '21" or 15"', '17-22', '10%', 'E, Q (x 10), R', '1', '7-42/8-48', 'See below', 'See below', '60%', 'Genius to supra-genius', 'Chaotic good', 'L (18''+ tall)', '101 to 200', 'B, C, D, E/Special', NULL, NULL, NULL, 'Titan.png', 'images/monsters/Titan.png', 'Titans normally dwell on a plane somewhere above the material, but occasionally they will visit the latter plane for various periods of time. Those dwelling on the Prime Material Plane for an extended period will acquire treasure as indicated above. To determine the armor class and hit dice of any given titan simply roll a 6-sided die: 1 = armor class 2 and 17 hit dice; 2 = 1 and 18; 3 = 0 and 19; 4 = -1 and 20; 5 = -2 and 21; and 6 = -3 and 22. Titans with only 17 or 18 hit dice move at 21 inches. Those with 21 or 22 hit dice do 8-48 hit points of damage per attack. Titans can become invisible at will. They can also levitate and/or become ethereal twice per day. All titans are able to employ both magic-user and clerical spells of 4th, 5th, 6th or even 7th level. To determine how many levels of spell use in each category a given titan possesses, simply roll a 4-sided die and add the result to 3. For each level of spell use, the titan can use 2 spells of each category, so the minimum number of magic spells possible for any titan is 8, and the same applies to clerical spells, 2 of 1st level, 2 of 2nd level, 2 of 3rd level, and 2 of 4th level. If specific titans are not prepared, simply determine which spells are known by any given titan at the time of encounter by random selection from the spell tables. The protection from evil spell of titans is of twice normal strength with respect to lawful evil beings. All titans possess 8 or more psionic abilities of the type possible for clerics. Roll two 6-sided dice and add the resulting number to a base of 6 to determine the total number of abilities. Ignore the ability of levitation. To determine psionic strength add the score rolled on percentile dice to a base of 100. They use all abilities at seventh mastery level. Psionic attacks have no effect on titans. In addition to their own language, titans are able to speak the six dialects of the races of giants. All titans are also conversant in the common tongue as well as that of chaotic good. Because of their particular predisposition, titans deal with storm giants on highly amicable terms. It is 20% probable that a storm giant will be with any single titan encountered. Titans appear very much as humans do, but they are all very muscular, handsome, and wear no facial hair. Their dress and armor appears Grecian.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (104, 'Toad, Giant', NULL, 'Common', '1-12', '6', '6" + 6" hop', '2 + 4', '0%', 'Nil', '1', '2-8', 'See below', 'Nil', 'Standard', 'Animal', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Toad,_Giant.png', 'images/monsters/Toad,_Giant.png', 'Giant toads are found in most regions. Although their smaller cousins are beneficial insect eaters, the large toads are prone to devour any creature which appears edible. All toads are capable of hopping their movement distance. This hop clears objects up to one-third the linear distance in height, and it requires but a single melee round to accomplish, and they can attack in mid-air or at the end of their leap.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (105, 'Toad, Ice', NULL, 'Rare', '1-4', '4', '9"', '5', '40%', 'C', '1', '3-12', 'See below', 'Nil', 'Standard', 'Average', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Toad,_Ice.png', 'images/monsters/Toad,_Ice.png', 'These creatures are found in cold climes or far beneath the surface of the ground. In addition to their typical abilities these monsters are able to radiate cold in a 1 inch radius from their body. All non-cold using creatures within 1 inch of the ice toad suffer 3-18 points of damage. The toad can do this but once every other melee round. The ice toads have their own weird language.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (106, 'Toad, Poisonous', NULL, 'Uncommon', '1-8', '7', '6" + 6" hop', '2', '0%', 'Nil', '1', '2-5', 'See below', 'Nil', 'Standard', 'Animal', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Toad,_Poisonous.png', 'images/monsters/Toad,_Poisonous.png', 'The poisonous type of giant toad is indistinguishable from non-poisonous toads. Their bite necessitates a saving throw versus poison, or the victim will die immediately.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (107, 'Treant', NULL, 'Rare', '1-20', '0', '12"', '7-12', '10%', 'Q (x 5), S', '2', '2-16/3-18/4-24 (See below)', 'See below', 'Never surprised', 'Standard', 'Very', 'Chaotic good', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Treant.png', 'images/monsters/Treant.png', 'Treants are strangely related to humans and trees, combining features of both species. They dwell in woods and forests and are basically indistinguishable from trees. They hate evil things or unrestrained use of fire. If need arises treants can actually cause trees to come to life, move 3 inches per turn, and attack as a full-grown treant, 2 attacks for 4-24 hit points of damage per attack. Aroused treants must be within 6 inches of a normal tree to cause it to move, and an individual treant can cause only one or two normal trees to move and attack as stipulated. Because of their body and skin structures, treants have a very superior armor class rating. However, against fire they lose this superiority. Attacks based on fire are at a +4 on to hit dice; treants save against such attacks at a -4, and fire damage dice are +1 hit point. Treants of small size, 12''-15'' tall, have 7 or 8 hit dice and do 2-16 hit points of damage per attack, middle-sized treants, 16''-19'', have 9-10 hit dice and attack damage of 3-18, and those of large size, 20''-23''+, have 11-12 hit dice and do 4-24 points of damage. Treants and treant-controlled trees cause 1 point of structural damage on fortifications, this is for both attacks possible to any given treant or treant-controlled tree, regardless of the size of the treant attacking. A treant lair will typically be a vast cave screened by many plants and trees. Treants resent greatly uninvited entrance into such a place.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (108, 'Troglodyte', NULL, 'Common', '10-100', '5', '12"', '2', '15%', 'A', '3 or 1', '1-3/1-3/2-5 or by weapon type', 'Revulsion odor', 'See below', 'Standard', 'Low', 'Chaotic evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Troglodyte.png', 'images/monsters/Troglodyte.png', 'Troglodytes are a race of reptilian humanoids who dwell in subterranean places. They loathe humans, and their aim is to slaughter all whom they encounter. Troglodytes have excellent infravision, 90 feet. For every 10 troglodytes encountered there will be 1 leader-type with 3 hit dice. For every 20 there will be an additional 2 leader types with 4 hit dice each. If 60 or more are encountered there will be a troglodyte chieftain with 6 hit dice, and 2-8 guards of 3 hit dice each. The lair of a tribe of troglodytes is typically a large cave or cavern with small chambers adjoining it in which the individual units live. A lair will contain females equal to 100% of the males. Females fight as 1 + 1 hit dice monsters. There will also be hatchlings and eggs, but these are of no importance. Troglodytes can attack with claws and teeth, but 50% of them use weapons of some type. The armed half of a group encountered will have: javelin (2) 25%, battle axe (stone) 10%, morning star (stone) 10%, sword 5%. Their javelins are great vaned darts which have a +3 chance to hit when used by troglodytes and cause 2-8 hit points damage. They shun armor. When aroused for battle, troglodytes emit a secretion which smells extremely disgusting to humans, including dwarves, elves, gnomes, half-elves and halflings. Those humans failing their saving throw versus poison are affected by revulsion so as to lose 1 point of strength per melee round for 1-6 rounds, cumulative. Loss of strength lasts 10 melee rounds after it has taken final effect. Troglodytes have a chameleon-like power, so they can change their skin coloration to shades of gray, brown or green. They thus surprise on a 1-4 unless they are angry and excreting their stench. They use this coloration to hide when an encounter goes against them.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (109, 'Troll', NULL, 'Uncommon', '1-12', '4', '12"', '6 + 6', '40%', 'D', '3', '5-8/5-8/2-12', 'See below', 'Regeneration', 'Standard', 'Low', 'Chaotic evil', 'L (9''+ tall)', 'Nil', 'Nil', NULL, NULL, NULL, 'Troll.png', 'images/monsters/Troll.png', 'Trolls are horrid carnivores found in nearly every clime. They are feared by most creatures, as a troll knows no fear and attacks unceasingly. Their sense of smell is very acute, their infravision is superior, 90 feet, and their strength is very great. A troll attacks with its clawed forelimbs and its great teeth. A troll is able to fight 3 different opponents at once. 3 melee rounds after being damaged, a troll will begin to regenerate. Regeneration repairs damage at 3 hit points per round; this regeneration includes the rebonding of severed members. The loathsome members of a troll have the ability to fight on even if severed from the body; a hand can claw or strangle, the head bite, etc. Total dismemberment will not slay a troll, for its parts will slither and scuttle together, rejoin, and the troll will arise whole and ready to continue combat. To kill a troll, the monster must be burned or immersed in acid, any separate pieces being treated in the same fashion or they create a whole again in 3-18 melee rounds. Troll hide is a nauseating moss green, mottled green and gray, or putrid gray. The writhing hair-like growth upon a troll''s head is greenish black or iron gray. The eyes of a troll are dull black.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (110, 'Turtle, Sea, Giant', NULL, 'Uncommon', '1-3', '2/5', '1"/15"', '15', '0%', 'Nil', '1', '4-16', 'Nil', 'See below', 'Standard', 'Non-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Turtle,_Sea,_Giant.png', 'images/monsters/Turtle,_Sea,_Giant.png', 'These basically non-aggressive marine creatures will fight fiercely if annoyed or threatened. If they surface beneath a small craft there is a possibility of upsetting the vessel, i.e. 90% for a long boat, 10% for a typical long ship. The head and flippers of the creature are armor class 5, but they can be withdrawn to make these areas armor class 3.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (111, 'Turtle, Snapping, Giant', NULL, 'Uncommon', '1-4', '0/5', '3"/2"', '10', '0%', 'Nil', '1', '6-24', 'See below', 'See below', 'Standard', 'Non-', 'Neutral', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Turtle,_Snapping,_Giant.png', 'images/monsters/Turtle,_Snapping,_Giant.png', 'Feared greatly for their voracious appetite and aggressiveness, giant snapping turtles are found in lakes and large rivers. They lurk near shore or on the bottom, as they do not swim quickly. They remain motionless, thus surprising on 1-4 out of 6, and then shoot forth their long neck, up to 10 feet long, to grab their prey. The head and limbs of these monsters are armor class 5, but they can be withdrawn to offer armor class 2.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (112, 'Umber Hulk', NULL, 'Rare', '1-4', '2', '6" (1"-6")', '8 + 8', '30%', 'G', '3', '3-12/3-12/2-10', 'Confusion', 'Nil', 'Standard', 'Average', 'Chaotic evil', 'L (8'' tall, 5'' wide)', 'Nil', 'Nil', NULL, NULL, NULL, 'Umber_Hulk.png', 'images/monsters/Umber_Hulk.png', 'Umber hulks are subterranean predators. Their iron-like claws enable them to burrow through solid stone at 1 inch per turn and through loam at fully 6 times that rate. Their prey includes young purple worms, ankheg, and similar monsters. However, the favorite prey of umber hulks are humans. They attack with claws and their powerful mandibles. Worse still, any intelligent creature which views the umber hulk''s four eyes squarely must save versus magic or be confused for 3-12 melee rounds. These creatures have their own language. Umber hulks are black, shading to yellowish gray on the front. Their head is gray on top, and the mandibles are ivory colored. Because of their dark color they can easily be mistaken for some humanoid creature at 40 feet or more distance.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (113, 'Unicorn', NULL, 'Rare', '2-5', '2', '24"', '4 + 4', '5%', 'X', '3', '1-6/1-6/1-12', 'Charge', 'See below', 'See below', 'Average', 'Chaotic good', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Unicorn.png', 'images/monsters/Unicorn.png', 'Unicorns dwell only in temperate woodlands, away from human habitation. These fierce but good creatures shun contact with all creatures except sprites, dryads and the like. Elven and human maids of pure heart and good alignment may sometimes, 25%, tame unicorns for use as steeds, and such are faithful, obedient mounts. Unicorns lair in open dells, their warded treasure kept in a nearby hollow tree, rocky niche, etc. When a unicorn charges into combat it does not strike with its two front hooves, but its horn strikes for double damage, 2-24. Because the unicorn is magical, its horn gains a bonus of +2 on to hit dice, and possession of a unicorn horn is a sovereign remedy against all forms of poison, gas included. Naturally, the unicorn is not subject to poison. A unicorn always senses the approach of an enemy at 24 inches distance. They move very silently and surprise opponents on a 1-5. Once per day unicorns are able to use a teleportation spell of limited distance, a dimension door, to appear up to 36 inches away from their former position. They may so teleport with a rider on their back. Unicorns make all saving throws as if they were magic-users of the 11th level. They cannot be charmed or held by magic. Death spells do not affect them. They speak their own language.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (114, 'Wight', NULL, 'Uncommon', '2-16', '5', '12"', '4 + 3', '70%', 'B', '1', '1-4', 'Energy drain', 'Silver or magic weapons to hit', 'See below', 'Average', 'Lawful evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Wight.png', 'images/monsters/Wight.png', 'The term wight has lost its old meaning of a person and come to stand for those undead humans who typically inhabit barrow mounds or catacombs. These creatures are most evil and hateful, seeking to destroy any life form they encounter. Wights shun bright lights and hate sunlight. Because these monsters exist simultaneously on the normal and negative planes of the material plane, they are affected only by silver or magical weapons. This existence allows them to drain life energy levels, one such level each time they score a hit on an opponent. The creature so hit loses the hit points of damage scored, 1-4, plus one experience level and all the bonuses derived from that level, i.e. hit dice, class bonuses, thief abilities, spell levels, etc. A 9th level magic user struck by a wight loses 1-4 hit points and he becomes an 8th level magic user; he has the spells and the hit points of an 8th level magic user, and he melees as an 8th level character of his class. Wights are not affected by sleep, charm, hold, or cold-based spells. Neither poison nor paralyzation harms wights. Holy water causes 2-8 hit points of damage for every vial-full which strikes. A raise dead spell will destroy a wight. Any human totally drained of life energy by a wight will become a half-strength wight under control of its slayer.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (115, 'Will-O-(the)-Wisp', NULL, 'Uncommon', '1 (or 1-3)', '-8', '18"', '9', '5%', 'Z', '1', '2-16', 'See below', 'See below', 'See below', 'Exceptional', 'Chaotic evil', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Will-O-(the)-Wisp.png', 'images/monsters/Will-O-(the)-Wisp.png', 'Will-o-wisps commonly haunt deserted, dangerous places such as bogs, fens, swamps, or catacombs where mires, quicksand, pit traps and the like are plentiful. A victim trapped by these hazards feeds the will-o-wisp as it expires, for the thing feeds upon the fleeing life force. Thus, will-o-wisps seek to lure prey to their doom. 10% of the time 1-3 are encountered, and in these cases the creatures'' lair will be nearby 90% of the time. The creature can attack, however, any hit causing 2-16 points of electrical damage to the opponent. A will-o-wisp is able to grow bright or very dim in order to confuse prey. It can move slowly or flit about. It can blank out its glow entirely for 2-8 melee rounds if it does not attack, and at that time it can be detected only by creatures able to see invisible objects. While any weapon will harm a will-o-wisp, most spells do not affect it. The only spells which can affect the creature are protection from evil, magic missile and maze. If brought to 5 or fewer remaining hit points a will-o-wisp will reveal its lair and give over its treasure. A will-o-wisp is a glowing sphere, looking like a lantern, torch or even a dancing lights spell effect. In combat they glow blue, violet or pale green.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (116, 'Wolf', NULL, 'Common', '2-20', '7', '18"', '2 + 2', '10%', 'Nil', '1', '2-5', 'Nil', 'Nil', 'Standard', 'Semi-', 'Neutral', 'S', 'Nil', 'Nil', NULL, NULL, NULL, 'Wolf.png', 'images/monsters/Wolf.png', 'These carnivores are found in wild forests from the arctic to the temperate zones. They always hunt in packs and if hungry, 75%, they will not hesitate to follow and attack prey, always seeking to strike at an unguarded moment. Their howling is 50% likely to panic herbivores which are not being held by humans and calmed. They love horsemeat. If encountered in their lair there is a 30% chance that there will be 1-4 cubs per pair of adult wolves. Cubs do not fight and can be trained as war dogs or hunting beasts.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (117, 'Wolf, Dire (Worg)', NULL, 'Rare', '3-12', '6', '18"', '3 + 3 (4 + 4)', '10%', 'Nil', '1', '2-8', 'Nil', 'Nil', 'Standard', 'Semi- (low)', 'Neutral (evil)', 'M (L)', 'Nil', 'Nil', NULL, NULL, NULL, 'Wolf,_Dire_(Worg).png', 'images/monsters/Wolf,_Dire_(Worg).png', 'This variety of wolf is simply a huge specimen typical of the Pleistocene Epoch. They conform to the characteristics of normal wolves. Evil natured, neo-dire wolves are known as worgs. These creatures have a language and are often found in co-operation with goblins in order to gain prey or to simply enjoy killing. They are as large as ponies and can be ridden. They otherwise conform to the characteristics of wolves.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (118, 'Wolf, Winter', NULL, 'Very rare', '2-8', '5', '18"', '6', '10%', 'I', '1', '2-8', 'Frost', 'Nil', 'Standard', 'Average', 'Neutral (evil)', 'L', 'Nil', 'Nil', NULL, NULL, NULL, 'Wolf,_Winter.png', 'images/monsters/Wolf,_Winter.png', 'The winter wolf is a horrid carnivore which inhabits only chill regions. It is of great size and foul disposition. Winter wolves can use their savage jaws or howl forth a blast of frost which will coat any creature within 1 inch of their muzzle. This frost causes 6-24 hit points damage, half that amount if a saving throw versus dragon breath is successful. The winter wolf is able to use the howling frost but once per 10 melee rounds. Cold-based attacks do not harm them, but fire-based attacks cause +1 per die of damage normally caused. They have their own language and can also converse with worgs. The coat of the winter wolf is glistening white or silvery, and its eyes are very pale blue or silvery. The pelt of the creature is valued at 5,000 gold pieces.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (119, 'Wraith', NULL, 'Uncommon', '2-12', '4', '12"/24"', '5 + 3', '25%', 'E', '1', '1-6', 'Energy drain', 'Silver or magic weapons to hit', 'See below', 'Very', 'Lawful evil', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Wraith.png', 'images/monsters/Wraith.png', 'Wraiths are undead, similar in nature to wights, but they exist more strongly on the negative material plane. They are found only in dark and gloomy places, for they have no power in full sunlight. In addition to the chilling effect of its touch, 1-6 hit points damage, a wraith drains one life energy level per hit, just as a wight does. Similarly, the wraith can be struck only with silver weapons, which cause only one-half damage, or weapons which are magically enchanted, which score full damage.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (120, 'Wyvern', NULL, 'Uncommon', '1-6', '3', '6"/24"', '7 + 7', '30%', 'E', '2', '2-16/1-6', 'Poison', 'Nil', 'Standard', 'Low', 'Neutral (evil)', 'L (35'' long)', 'Nil', 'Nil', NULL, NULL, NULL, 'Wyvern.png', 'images/monsters/Wyvern.png', 'Wyverns are distantly related to dragons. These monsters also inhabit places favored by dragons, tangled forests, great caverns, and the like. They are rather stupid, but very aggressive, and wyverns will always attack. The wyvern bites, 2-16, and lashes with its sting-equipped tail at one or two opponents. Any creature struck by this tail must save versus poison or die. Even if the victim makes its saving throw, it takes 1-6 points of damage. Note that the tail is very long and mobile, easily striking over the back of the wyvern to hit an opponent before its front. Wyverns are dark brown to gray. Their eyes are orange or red.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
INSERT INTO [monsters] ([monster_id], [name], [category], [frequency], [number_appearing], [armor_class], [move], [hit_dice], [percent_in_lair], [treasure_type], [number_of_attacks], [damage], [special_attacks], [special_defenses], [magic_resistance], [intelligence], [alignment], [size], [psionic_ability], [attack_defense_modes], [chance_speaking], [chance_magic_use], [chance_sleeping], [image], [image_path], [description], [notes], [source_file], [imported_at], [attack_hd_override_text]) VALUES (121, 'Zombie', NULL, 'Rare', '3-24', '8', '6"', '2', 'Nil', 'Nil', '1', '1-8', 'Nil', 'Nil', 'See below', 'Non-', 'Neutral', 'M', 'Nil', 'Nil', NULL, NULL, NULL, 'Zombie.png', 'images/monsters/Zombie.png', 'Zombies are magically animated corpses, undead creatures under the command of the evil magic-users or clerics who animated them. These creatures follow commands, as spoken on the spot or as given previously, of limited length and complication, a dozen words or so. Zombies are typically found near graveyards, in dungeons, and in similar charnel places. Zombies are slow, always striking last, but always doing 1-8 hit points of damage when they hit. They always fight until destroyed and nothing short of a cleric can turn them back. Sleep, charm, hold and cold-based spells do not affect zombies. Holy water vials score 2-8 hit points of damage for each one which strikes.', NULL, 'monsters_1e_master_final.csv', '2026-04-12 19:50:09', NULL);
