INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (1, 'Sleep', 'magic_user', 1, NULL, NULL, '30 ft + 10 ft/level', '5 rounds/level', '15-ft radius', NULL, '1 segment', '', 'Puts a number of low-HD creatures into magical slumber.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_1_sleep', 'sleep', 247, 'Puts a number of low-HD creatures into magical slumber.', 'One of the strongest low-level crowd-control spells in 1e, especially against weak foes.', 'Can be used for capture, escape, and bypassing guards.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (2, 'Read Magic', 'magic_user', 1, NULL, NULL, 'Caster', 'Short', 'Caster', NULL, '1 round', '', 'Allows the caster to read magical writing and inscriptions.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_1_read_magic', 'read_magic', 244, 'Allows the caster to read magical writing and inscriptions.', 'Little direct combat value.', 'Essential for reading scrolls, spellbooks, and arcane writings.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (3, 'Shield', 'magic_user', 1, NULL, NULL, 'Caster', '5 rounds/level', 'Caster', NULL, '1 segment', '', 'Creates a magical barrier that improves defense against frontal attacks and missiles.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_1_shield', 'shield', 245, 'Creates a magical barrier that improves defense against frontal attacks and missiles.', 'Excellent self-defense spell, especially against missile fire and magic missile.', 'Primarily combat-focused.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (4, 'Ventriloquism', 'magic_user', 1, NULL, NULL, 'Moderate', 'Short', 'Projected voice point', NULL, '1 segment', 'None or Special', 'Projects the caster''s voice so it seems to come from another location.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_1_ventriloquism', 'ventriloquism', 250, 'Projects the caster''s voice so it seems to come from another location.', 'Useful for distraction, false orders, and ambush misdirection.', 'Excellent for trickery, performance, and stealthy diversions.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (5, 'Invisibility', 'magic_user', 2, NULL, NULL, 'Touch', 'Special', '1 creature or object up to creature size', NULL, '2 segments', '', 'Renders the target invisible until broken by attack or other disallowed action.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_2_invisibility', 'invisibility', 261, 'Renders the target invisible until broken by attack or other disallowed action.', 'Powerful for ambushes, retreats, scouting, and repositioning.', 'One of the best exploration, infiltration, and escape spells in the game.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (6, 'Knock', 'magic_user', 2, NULL, NULL, '60 ft', 'Instantaneous', '1 door, box, gate, chest, or portal', NULL, '1 segment', '', 'Magically opens locked, stuck, barred, or wizard-locked closures within limits.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_2_knock', 'knock', 262, 'Magically opens locked, stuck, barred, or wizard-locked closures within limits.', 'Can rapidly open escape routes or bypass defensive barriers.', 'Excellent dungeon access and anti-lock utility.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (7, 'Fireball', 'magic_user', 3, NULL, NULL, '10 in + 1 in/level', 'Instantaneous', '33,000 cubic ft', NULL, '3 segments', 'Half damage', 'Creates a burst of magical fire that deals 1d6 damage per caster level.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_3_fireball', 'fireball', 281, 'Creates a burst of magical fire that deals 1d6 damage per caster level.', 'Signature area-damage spell and devastating against grouped foes.', 'Can burn barriers, ignite materials, and clear masses of weak enemies.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (8, 'Charm Monster', 'magic_user', 4, NULL, NULL, '3 in', 'Special', '1 or more creatures within 3 ft of each other', NULL, '4 segments', 'Negates', 'Charms one or more monsters so they regard the caster as a trusted ally.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_4_charm_monster', 'charm_monster', 299, 'Charms one or more monsters so they regard the caster as a trusted ally.', 'Can neutralize or convert dangerous creatures if they fail their saves.', 'Useful for negotiation, obtaining aid, and bypassing hostile encounters.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (9, 'Dimension Door', 'magic_user', 4, NULL, NULL, '1 in/level', 'Instantaneous', 'Caster', NULL, '4 segments', '', 'Instantly transports the caster to a chosen location within range.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_4_dimension_door', 'dimension_door', 302, 'Instantly transports the caster to a chosen location within range.', 'Excellent for escape, repositioning, bypassing obstacles, and surprise movement.', 'One of the best mobility spells for exploration and infiltration.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (10, 'Hallucinatory Terrain', 'magic_user', 4, NULL, NULL, '2 in/level', 'Permanent until touched or dispelled', '1 in square/level', NULL, '1 turn', '', 'Creates a large-scale visual illusion that disguises terrain features.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_4_hallucinatory_terrain', 'hallucinatory_terrain', 309, 'Creates a large-scale visual illusion that disguises terrain features.', 'Can hide forces, routes, or hazards and mislead approaching enemies.', 'Excellent for concealment, lairs, ambush sites, and deception.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (11, 'Polymorph Self', 'magic_user', 4, NULL, NULL, '0', '2 turns/level', 'Caster', NULL, '4 segments', '', 'Allows the caster to assume another physical form with many of its movement modes.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'magic_user_4_polymorph_self', 'polymorph_self', 316, 'Allows the caster to assume another physical form with many of its movement modes.', 'Can grant mobility, unusual attack options, or escape capability.', 'Excellent for infiltration, movement, scouting, and versatility.', 'conservative_phb_osric_cleanup_pass');
INSERT INTO [spells] ([spell_id], [name], [class_name], [spell_level], [notes], [school], [range_text], [duration], [area_of_effect], [components], [casting_time], [saving_throw], [description], [source_file], [imported_at], [external_spell_id], [normalized_name], [source_row], [summary_text], [combat_use_text], [utility_use_text], [audit_note]) VALUES (12, 'Bless', 'cleric', 1, NULL, NULL, '60 ft', '6 rounds', '50-ft square', NULL, '1 round', '', 'Grants allies a divine bonus to morale and attack effectiveness; reverse is usually Bane.', 'docs\reference\adnd_1e_master_spells_audited.csv', '2026-04-13 15:14:54', 'cleric_1_bless', 'bless', 2, 'Grants allies a divine bonus to morale and attack effectiveness; reverse is usually Bane.', 'Strong early party buff before melee begins.', 'Useful for rites, blessings, and morale-heavy scenes.', 'conservative_phb_osric_cleanup_pass');
